  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f463adf-346b-56d6-9071-457cd9bd6c0a', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'أيّ من الأعداد التالية عددٌ صمّاء (غير ناطق)؟', '[{"id":"a","text":"√16"},{"id":"b","text":"√7"},{"id":"c","text":"0.25"},{"id":"d","text":"−4/3"}]'::jsonb, 'b', '√16 = 4 عدد ناطق، و0.25 = 1/4 ناطق، و−4/3 كسر ناطق. أمّا √7 فجذر عدد ليس مربّعًا كاملًا، إذن هو عدد صمّاء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fbcfc1b-1b2d-58d7-b16b-bdf0c6069898', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما ناتج العملية: (−2)³ + (−5) × (−3) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"23"},{"id":"c","text":"−23"},{"id":"d","text":"1"}]'::jsonb, 'a', 'نحسب القوّة أوّلًا: (−2)³ = −8، ثمّ الضرب: (−5) × (−3) = 15. أخيرًا الجمع: −8 + 15 = 7. التحقّق: −8 + 15 = 7 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35e76788-e657-5be4-b93d-43064799b43d', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما قيمة |2 − 9| + |−3| ؟', '[{"id":"a","text":"10"},{"id":"b","text":"4"},{"id":"c","text":"−4"},{"id":"d","text":"−10"}]'::jsonb, 'a', '2 − 9 = −7 إذن |2 − 9| = 7، و|−3| = 3. المجموع = 7 + 3 = 10. القيمة المطلقة دائمًا موجبة أو معدومة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d51ef99d-e6b4-5655-b4fc-8c69e0cd2e97', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'أيّ عدد ينتمي إلى المجال ]−2 ، 5] ؟', '[{"id":"a","text":"5"},{"id":"b","text":"−2"},{"id":"c","text":"6"},{"id":"d","text":"−3"}]'::jsonb, 'a', 'المجال ]−2 ، 5] يعني −2 < x ≤ 5: الحدّ −2 غير مشمول (قوس متّجه للخارج) و5 مشمول. إذن 5 ينتمي، بينما −2 لا (مستثنى)، و6 و−3 خارج المجال.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b9aed72-616e-58c5-abc9-9a362e2cff71', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'رتّب الأعداد التالية تصاعديًّا: √2 ، 1 ، 1.5 ، √3 . ما الترتيب الصحيح؟', '[{"id":"a","text":"1 < √2 < 1.5 < √3"},{"id":"b","text":"1 < 1.5 < √2 < √3"},{"id":"c","text":"√2 < 1 < √3 < 1.5"},{"id":"d","text":"1 < √3 < √2 < 1.5"}]'::jsonb, 'a', '√2 ≈ 1.414 و√3 ≈ 1.732. إذن الترتيب التصاعدي: 1 < 1.414 < 1.5 < 1.732، أي 1 < √2 < 1.5 < √3.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a930d86d-1fb6-548b-a1ad-81bbae7bb2b8', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'إذا كان a < b وc عدد سالب (c < 0)، فأيّ عبارة صحيحة دائمًا؟', '[{"id":"a","text":"a × c > b × c"},{"id":"b","text":"a × c < b × c"},{"id":"c","text":"a + c > b + c"},{"id":"d","text":"a × c = b × c"}]'::jsonb, 'a', 'الضرب في عدد سالب يقلب اتّجاه المتراجحة: من a < b نحصل على a × c > b × c. مثال: 2 < 3 و c = −1 تعطي −2 > −3 ✓. أمّا الجمع (الخيار c) فيحفظ الترتيب فيكون a + c < b + c.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a59fdfa4-f8c5-5e02-ade5-d6bf905d445e', '65871a90-e921-55ff-b1fe-5483ab510aad', 'math', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
