  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6a118a4-cd9d-5c70-895e-0cff5a81a44c', '5680c5e9-d223-542e-9db3-4c3e770da622', 'أيّ من العبارات التالية صحيحة؟', '[{"id":"a","text":"√(9 + 16) = 3 + 4"},{"id":"b","text":"√(9 × 16) = 3 × 4"},{"id":"c","text":"√(−4) = 2"},{"id":"d","text":"√(a²) = a دائمًا"}]'::jsonb, 'b', 'خاصيّة جذر الجداء: √(9×16) = √9 × √16 = 12. أمّا الجمع فلا خاصيّة له، ولا جذر لعدد سالب، و √(a²)=|a|.', 5)
