INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4908721-72aa-51ae-8b71-e22a8b633ea4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'أبسّط √98 :', '[{"id":"a","text":"7√2"},{"id":"b","text":"49√2"},{"id":"c","text":"2√7"},{"id":"d","text":"14√2"}]'::jsonb, 'a', 'نحلّل 98 إلى جداء مربّع كامل: 98 = 49 × 2. إذن √98 = √(49 × 2) = √49 × √2 = 7√2. التحقّق: (7√2)² = 49 × 2 = 98 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
