INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c26c3dc4-2755-56a0-9961-ea04bd7ee7c4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة √50 − √18 ؟', '[{"id":"a","text":"2√2"},{"id":"b","text":"√32"},{"id":"c","text":"8√2"},{"id":"d","text":"√2"}]'::jsonb, 'a', 'نبسّط: √50 = √(25×2) = 5√2 و√18 = √(9×2) = 3√2. إذن √50 − √18 = 5√2 − 3√2 = 2√2. الخيار (b) خطأ لأنّ √a − √b ≠ √(a−b).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32c26bd5-1576-575b-ae80-09b2672b01e1', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'اُنطق مقام الكسر 10/√5 (اكتبه بدون جذر في المقام):', '[{"id":"a","text":"2√5"},{"id":"b","text":"10√5"},{"id":"c","text":"√5"},{"id":"d","text":"√5/2"}]'::jsonb, 'a', 'نضرب البسط والمقام في √5: (10 × √5) / (√5 × √5) = 10√5 / 5 = 2√5. التحقّق: 2√5 = 2√5، ومربّعه (2√5)²=20 و(10/√5)²=100/5=20 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1549de7d-0f12-56b6-9248-0b5c3af6058d', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة √((−7)²) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"−7"},{"id":"c","text":"49"},{"id":"d","text":"−49"}]'::jsonb, 'a', '(−7)² = 49 ثمّ √49 = 7. وبصفة عامّة √(a²) = |a|، و|−7| = 7. الجذر التربيعي لا يُعطي أبدًا قيمة سالبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6a56b2b-f341-5e7c-aab5-a7874fe60fdf', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة (3 + √5)(3 − √5) ؟', '[{"id":"a","text":"4"},{"id":"b","text":"9 + √5"},{"id":"c","text":"14"},{"id":"d","text":"6"}]'::jsonb, 'a', 'هذا فرق مربّعين: (a+b)(a−b) = a² − b² مع a = 3 وb = √5. إذن = 3² − (√5)² = 9 − 5 = 4.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9527c06-59ec-5c8d-9092-411f79da8814', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'مربّع مساحته 72 cm². ما طول ضلعه بالصورة المبسّطة؟', '[{"id":"a","text":"6√2 cm"},{"id":"b","text":"36 cm"},{"id":"c","text":"8√2 cm"},{"id":"d","text":"2√6 cm"}]'::jsonb, 'a', 'ضلع المربّع = √(المساحة) = √72. نبسّط: √72 = √(36×2) = 6√2 cm. التحقّق: (6√2)² = 36×2 = 72 ✓. أمّا 8√2 فمربّعه 128، و2√6 فمربّعه 24، وكلاهما خطأ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

