INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07e290b9-dd4c-578c-b221-a26ee2844bd3', '78d50116-f2e7-55df-8c02-20811ed38ef2', 'ما الصورة المنشورة لـ (x + 4)² ؟', '[{"id":"a","text":"x² + 16"},{"id":"b","text":"x² + 4x + 16"},{"id":"c","text":"x² + 8x + 16"},{"id":"d","text":"x² + 8x + 8"}]'::jsonb, 'c', 'نطبّق (a+b)² = a²+2ab+b² حيث a=x و b=4: x² + 2(x)(4) + 4² = x² + 8x + 16.', 2)
