INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4d103ce-914f-5a57-980d-5aee80393d48', '78d50116-f2e7-55df-8c02-20811ed38ef2', 'ما ناتج نشر (x − 3)(x + 3) ؟', '[{"id":"a","text":"x² − 9"},{"id":"b","text":"x² + 9"},{"id":"c","text":"x² − 6x − 9"},{"id":"d","text":"x² − 6x + 9"}]'::jsonb, 'a', 'هذه هي المتطابقة الثالثة (a−b)(a+b) = a²−b² حيث a=x و b=3: x² − 3² = x² − 9.', 3)
