  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41274feb-9105-5e32-a1b5-63850f1aaf87', 'ab49794e-9915-51a9-aaa0-c4a4eec3bf53', 'باستخدام المتطابقات الشهيرة، ما قيمة 103² ؟', '[{"id":"a","text":"10609"},{"id":"b","text":"10309"},{"id":"c","text":"10600"},{"id":"d","text":"10906"}]'::jsonb, 'a', '103² = (100 + 3)² = 100² + 2(100)(3) + 3² = 10000 + 600 + 9 = 10609.', 4)
