INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2df687dd-026a-5241-a911-ef698f832390', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'انشر العبارة: (2x − 3)² ؟', '[{"id":"a","text":"4x² − 12x + 9"},{"id":"b","text":"4x² + 9"},{"id":"c","text":"2x² − 12x + 9"},{"id":"d","text":"4x² − 6x + 9"}]'::jsonb, 'a', 'مربّع الفرق: (a − b)² = a² − 2ab + b² مع a = 2x وb = 3. إذن (2x)² − 2(2x)(3) + 3² = 4x² − 12x + 9. الخيار (b) نسي الحدّ الأوسط −12x.', 2)
