INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7817946-d5ac-52f9-bf22-b14019574756', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل العبارة: 3x² − 12 ؟', '[{"id":"a","text":"3(x − 2)(x + 2)"},{"id":"b","text":"3(x² − 12)"},{"id":"c","text":"(3x − 12)(x + 1)"},{"id":"d","text":"3(x − 4)(x + 4)"}]'::jsonb, 'a', 'نُخرج العامل المشترك 3 أوّلًا: 3x² − 12 = 3(x² − 4). ثمّ x² − 4 = x² − 2² فرق مربّعين = (x − 2)(x + 2). النتيجة: 3(x − 2)(x + 2).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
