INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('511c23a6-5988-581b-8e8b-93cd092ff15b', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'احسب 99² باستخدام المتطابقات الشهيرة:', '[{"id":"a","text":"9801"},{"id":"b","text":"9999"},{"id":"c","text":"9601"},{"id":"d","text":"9802"}]'::jsonb, 'a', '99² = (100 − 1)² = 100² − 2(100)(1) + 1² = 10000 − 200 + 1 = 9801.', 4)
