INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4cb0049-893e-5942-a530-94978dcf447e', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل العبارة: x² + 6x + 9 − y² ؟', '[{"id":"a","text":"(x + 3 − y)(x + 3 + y)"},{"id":"b","text":"(x + 3)² − y"},{"id":"c","text":"(x + 3 − y)²"},{"id":"d","text":"(x − 3 − y)(x − 3 + y)"}]'::jsonb, 'a', 'نلاحظ x² + 6x + 9 = (x + 3)². إذن العبارة = (x + 3)² − y² وهي فرق مربّعين: = (x + 3 − y)(x + 3 + y).', 5)
