INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65e9e164-344c-51fe-be98-0f1ee955336b', '077b13ed-9e9e-5de9-980e-b78558e1e754', 'ما الشكل العامّ للمعادلة من الدرجة الأولى بمجهول واحد؟', '[{"id":"a","text":"ax² + bx + c = 0 حيث a ≠ 0"},{"id":"b","text":"ax + b = 0 حيث a ≠ 0"},{"id":"c","text":"ax + b = 0 حيث a = 0"},{"id":"d","text":"a/x + b = 0 حيث x ≠ 0"}]'::jsonb, 'b', 'المعادلة من الدرجة الأولى بمجهول واحد هي ax + b = 0 حيث a ≠ 0. إذا كانت ax² فهي من الدرجة الثانية؛ وإذا كان a = 0 انعدم المجهول ولم تعد من الدرجة الأولى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffe655bb-d1b1-569f-afcf-60477e4370ce', '077b13ed-9e9e-5de9-980e-b78558e1e754', 'ما ينصّ عليه مبدأ الجداء المعدوم؟', '[{"id":"a","text":"إذا كان a + b = 0 فإنّ a = 0 أو b = 0"},{"id":"b","text":"إذا كان a × b = 0 فإنّ a = 0 وb = 0 معًا بالضرورة"},{"id":"c","text":"إذا كان a × b = 0 فإنّ a = 0 أو b = 0 (أو كلاهما)"},{"id":"d","text":"إذا كان a × b = 0 فإنّ a = b"}]'::jsonb, 'c', 'مبدأ الجداء المعدوم: a × b = 0 ⟺ a = 0 أو b = 0. يكفي أن يكون أحدهما صفرًا. هذا المبدأ لا يُطبَّق على الجمع: a + b = 0 لا يستلزم أن يكون أحدهما صفرًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93c20c77-f0dc-54a8-8cc3-7ceaf7baf1dd', '077b13ed-9e9e-5de9-980e-b78558e1e754', 'ما الفرق الجوهري بين المعادلة والمتراجحة من حيث طبيعة الحلّ؟', '[{"id":"a","text":"المعادلة لا حلّ لها بينما المتراجحة لها دائمًا حلّ"},{"id":"b","text":"المعادلة حلّها عدد محدّد؛ أمّا المتراجحة فحلّها مجموعة لا نهائية من الأعداد (مجال)"},{"id":"c","text":"المتراجحة تستخدم علامة = بينما المعادلة تستخدم < أو >"},{"id":"d","text":"لا فرق بينهما من حيث طبيعة الحلّ"}]'::jsonb, 'b', 'المعادلة تُعطي عددًا واحدًا (أو عددًا محدودًا من الحلول)، بينما المتراجحة تُعطي مجموعةً من الأعداد تُمثَّل بمجال على المستقيم العددي، مثل x ∈ ]−∞ ؛ 5[.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f510218-ea82-563e-b2f5-19e116aa3908', '077b13ed-9e9e-5de9-980e-b78558e1e754', 'متى تنقلب إشارة التراجح عند حلّ متراجحة من الدرجة الأولى؟', '[{"id":"a","text":"عند إضافة عدد موجب إلى طرفَيها"},{"id":"b","text":"عند طرح عدد من طرفَيها"},{"id":"c","text":"عند نقل حدّ من طرف إلى الطرف الآخر"},{"id":"d","text":"عند الضرب أو القسمة على عدد سالب"}]'::jsonb, 'd', 'تنقلب إشارة التراجح فقط عند الضرب أو القسمة على عدد سالب. أمّا الجمع أو الطرح أو الضرب والقسمة على عدد موجب فلا تُغيّر الإشارة.', 4)
