INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1003cd5b-33ef-50a8-a5a0-de63f029f7de', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'بتطبيق مبدأ الجداء المعدوم، ما مجموعة حلول المعادلة: (2x − 6)(x + 4) = 0 ؟', '[{"id":"a","text":"{ 6 ، −4 }"},{"id":"b","text":"{ −3 ، 4 }"},{"id":"c","text":"{ −6 ، 4 }"},{"id":"d","text":"{ 3 ، −4 }"}]'::jsonb, 'd', 'جداء عددين يساوي الصفر يعني أنّ أحدهما صفر. إمّا 2x − 6 = 0 فنجد 2x = 6 أي x = 3، وإمّا x + 4 = 0 فنجد x = −4. مجموعة الحلول هي {3 ، −4}. التحقّق: (2×3−6)(3+4) = 0×7 = 0 ✓ و (2×(−4)−6)(−4+4) = (−14)×0 = 0 ✓', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6a1c117-1596-5121-8277-92cd7a7570cd', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'ما حلّ المتراجحة: 4x + 3 < 2x − 5 ؟', '[{"id":"a","text":"x < 4"},{"id":"b","text":"x < −4"},{"id":"c","text":"x > −4"},{"id":"d","text":"x > 4"}]'::jsonb, 'b', 'ننقل الحدود: 4x − 2x < −5 − 3، فنجد 2x < −8، ونقسم على 2 (عدد موجب لا قلب في الإشارة): x < −4. الحلّ هو x ∈ ]−∞ ، −4[. تحقّق بقيمة مثلًا x = −5: 4(−5)+3 = −17 و 2(−5)−5 = −15، وفعلًا −17 < −15 ✓', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2c73317-f59c-53e8-b54a-1ae8a4e18434', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'ما حلّ المعادلة: 2(3x − 1) + 4 = 3(x + 2) ؟', '[{"id":"a","text":"x = 2"},{"id":"b","text":"x = 1"},{"id":"c","text":"x = 4/3"},{"id":"d","text":"x = −4/3"}]'::jsonb, 'c', 'نوسّع الأقواس: 6x − 2 + 4 = 3x + 6، أي 6x + 2 = 3x + 6. ننقل الحدود: 6x − 3x = 6 − 2، فنجد 3x = 4، إذن x = 4/3. التحقّق: 2(3 × 4/3 − 1) + 4 = 2(4 − 1) + 4 = 6 + 4 = 10، و 3(4/3 + 2) = 3(10/3) = 10 ✓', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('340f0056-37f0-57a2-b63c-36810c7977cb', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'عمر أحمد ضعف عمر أخته سلمى، وبعد 4 سنوات يصبح مجموع عمريهما 41 سنة. ما عمر أحمد الآن؟', '[{"id":"a","text":"22 سنة"},{"id":"b","text":"18 سنة"},{"id":"c","text":"30 سنة"},{"id":"d","text":"20 سنة"}]'::jsonb, 'a', 'لتكن x عمر سلمى الآن، فعمر أحمد الآن 2x. بعد 4 سنوات: (2x + 4) + (x + 4) = 41، أي 3x + 8 = 41، فـ 3x = 33، إذن x = 11. عمر أحمد = 2 × 11 = 22 سنة. التحقّق: بعد 4 سنوات يكون 26 + 15 = 41 ✓', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc0e95d3-8aac-5a04-a61b-b5dff4c9bee1', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'محيط مستطيل يساوي 46 سم، وطوله يزيد على عرضه بـ 7 سم. ما طول هذا المستطيل؟', '[{"id":"a","text":"8 سم"},{"id":"b","text":"12 سم"},{"id":"c","text":"14 سم"},{"id":"d","text":"15 سم"}]'::jsonb, 'd', 'لتكن l الطول وw العرض. الطول يزيد على العرض بـ 7: l = w + 7. المحيط: 2(l + w) = 46 أي l + w = 23. بالتعويض: (w + 7) + w = 23، فـ 2w = 16، إذن w = 8 سم والطول l = 8 + 7 = 15 سم. التحقّق: 2(15 + 8) = 2 × 23 = 46 ✓', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88a2297f-a028-5f5d-8a94-3e63c6138a9e', 'ec6351c9-f945-5e92-a049-63e7ef8fc361', 'ما مجموعة حلول المتراجحة: −5x + 3 < 2x − 11 ؟', '[{"id":"a","text":"x < −2"},{"id":"b","text":"x > 2"},{"id":"c","text":"x < 2"},{"id":"d","text":"x > −2"}]'::jsonb, 'b', 'ننقل الحدود: −5x − 2x < −11 − 3، فـ −7x < −14. نقسم على −7 (عدد سالب → نقلب الإشارة!): x > 2. الحلّ هو x ∈ ]2 ، +∞[. تحقّق بـ x = 3: −5(3)+3 = −12 و 2(3)−11 = −5، وفعلًا −12 < −5 ✓', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'b9d33015-226b-5d6f-8109-8f164dfe2e07', 'math', '👑 تحدّي النخبة: معادلات ومتراجحات', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
