INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('361fc9f5-e27e-5944-8667-f152b54c1830', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'ما حلّ المعادلة: (x + 3)² − (x − 2)(x + 4) = 25 ؟', '[{"id":"a","text":"x = 2"},{"id":"b","text":"x = 1"},{"id":"c","text":"x = 3"},{"id":"d","text":"x = 4"}]'::jsonb, 'a', 'نوسّع الجداءين: (x + 3)² = x² + 6x + 9، و(x − 2)(x + 4) = x² + 2x − 8. المعادلة تصبح: (x² + 6x + 9) − (x² + 2x − 8) = 25. نبسّط: x² + 6x + 9 − x² − 2x + 8 = 25، أي 4x + 17 = 25. نطرح 17: 4x = 8، نقسم على 4: x = 2. التحقّق: (5)² − (0)(6) = 25 − 0 = 25 ✓', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63922c25-d692-5d77-a94e-a1d6195cc4e1', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'ما حلّ المعادلة: 4(x − 3) + 2(2x + 1) = 3(2x − 1) + 5 ؟', '[{"id":"a","text":"x = 4"},{"id":"b","text":"x = 6"},{"id":"c","text":"x = 1"},{"id":"d","text":"x = −6"}]'::jsonb, 'b', 'نوسّع جميع الأقواس: 4x − 12 + 4x + 2 = 6x − 3 + 5. نجمع الحدود المتشابهة: 8x − 10 = 6x + 2. ننقل: 8x − 6x = 2 + 10، أي 2x = 12. نقسم على 2: x = 6. التحقّق: 4(3) + 2(13) = 12 + 26 = 38 و 3(11) + 5 = 33 + 5 = 38 ✓', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c283733e-c9cd-567b-b259-4728ffa8b56e', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'ما مجموعة حلول المعادلة: (3x − 9)(2x + 4) = 0 ؟', '[{"id":"a","text":"{ 3 ، 2 }"},{"id":"b","text":"{ −3 ، 2 }"},{"id":"c","text":"{ 9 ، −4 }"},{"id":"d","text":"{ 3 ، −2 }"}]'::jsonb, 'd', 'نطبّق مبدأ الجداء المعدوم: (3x − 9)(2x + 4) = 0. إمّا 3x − 9 = 0، أي 3x = 9، فـ x = 3. أو 2x + 4 = 0، أي 2x = −4، فـ x = −2. مجموعة الحلول: {3 ، −2}. تنبيه: الأخطاء الشائعة هي أخذ 9 و−4 مباشرةً دون الحلّ، أو نسيان إشارة −2.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf0aefea-d3fa-5489-a1c6-f19da708013f', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'محيط مستطيل يساوي 54 سم، وطوله يفوق عرضه بـ 9 سم. ما طول المستطيل ؟', '[{"id":"a","text":"15 سم"},{"id":"b","text":"21 سم"},{"id":"c","text":"18 سم"},{"id":"d","text":"27 سم"}]'::jsonb, 'c', 'لتكن عرض المستطيل x سم، فطوله (x + 9) سم. المحيط = 2(الطول + العرض) = 54، إذن: 2(x + 9 + x) = 54. نبسّط: 2(2x + 9) = 54، أي 4x + 18 = 54. نطرح 18: 4x = 36، نقسم على 4: x = 9 سم (العرض). الطول = 9 + 9 = 18 سم. التحقّق: 2(18 + 9) = 2 × 27 = 54 سم ✓', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58a42a35-f0fe-5aac-9f86-63e9672764ae', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'ما مجموعة حلول المتراجحة المزدوجة: −3 ≤ 2x − 5 < 7 ؟', '[{"id":"a","text":"x ∈ ]1 ، 6["},{"id":"b","text":"x ∈ [1 ، 6]"},{"id":"c","text":"x ∈ [−1 ، 6["},{"id":"d","text":"x ∈ [1 ، 6["}]'::jsonb, 'd', 'نحلّ المتراجحة المزدوجة بإجراء العمليات على الأطراف الثلاثة معًا: −3 ≤ 2x − 5 < 7. نجمع 5 للأطراف الثلاثة: −3 + 5 ≤ 2x < 7 + 5، أي 2 ≤ 2x < 12. نقسم على 2 (موجب، لا قلب): 1 ≤ x < 6. الحلّ: x ∈ [1 ، 6[. الطرف 1 مشمول (≤) والطرف 6 غير مشمول (<).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e1f89e1-b7ac-5938-8e27-968c3af86ae6', 'a8c0434f-5209-5621-8ed6-1191bb23f2e2', 'عمر أحمد يساوي ثلاثة أضعاف عمر أخيه بلال. بعد 8 سنوات، يكون مجموع عمريهما 48 سنة. ما عمر أحمد الآن ؟', '[{"id":"a","text":"18 سنة"},{"id":"b","text":"24 سنة"},{"id":"c","text":"21 سنة"},{"id":"d","text":"30 سنة"}]'::jsonb, 'b', 'لنضع عمر بلال الآن = x سنة، فعمر أحمد = 3x سنة. بعد 8 سنوات: عمر أحمد = 3x + 8، وعمر بلال = x + 8. المعادلة: (3x + 8) + (x + 8) = 48. نبسّط: 4x + 16 = 48. نطرح 16: 4x = 32، نقسم على 4: x = 8 سنة (عمر بلال). عمر أحمد = 3 × 8 = 24 سنة. التحقّق: (24 + 8) + (8 + 8) = 32 + 16 = 48 ✓', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

