INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e19be12-fd67-5acc-8f8f-2750647b9e20', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المعادلة: 3(x − 2) + 5 = 2x + 4 ؟', '[{"id":"a","text":"x = 5"},{"id":"b","text":"x = 3"},{"id":"c","text":"x = −5"},{"id":"d","text":"x = 1"}]'::jsonb, 'a', 'نوسّع: 3x − 6 + 5 = 2x + 4 → 3x − 1 = 2x + 4 → 3x − 2x = 4 + 1 → x = 5. التحقّق: 3(3) + 5 = 14 و2(5) + 4 = 14 ✓.', 1)
