INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aee6b3c0-1493-5bf3-bca1-1abcffee50ba', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 3x − 7 < x + 5 ؟', '[{"id":"a","text":"x < 6"},{"id":"b","text":"x > 6"},{"id":"c","text":"x < 1"},{"id":"d","text":"x > −6"}]'::jsonb, 'a', '3x − 7 < x + 5 → 3x − x < 5 + 7 → 2x < 12 → نقسم على 2 (موجب) → x < 6. لا قلب للإشارة لأنّ المعامل موجب.', 3)
