  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('704d9e48-2a96-5829-9890-9ba9ac687b65', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 4 − 3x ≥ 19 ؟', '[{"id":"a","text":"x ≤ −5"},{"id":"b","text":"x ≥ −5"},{"id":"c","text":"x ≤ 5"},{"id":"d","text":"x ≥ 5"}]'::jsonb, 'a', '4 − 3x ≥ 19 → −3x ≥ 15 → نقسم على −3 مع قلب الإشارة → x ≤ −5. التحقّق بـ x = −5: 4 − 3(−5) = 19 ≥ 19 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bd527cf-ae89-582d-9e03-767d3ff59e49', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما مجموعة الأعداد الصحيحة x التي تحقّق في آنٍ واحد: x > −2 و2x ≤ 6 ؟', '[{"id":"a","text":"{ −1 ، 0 ، 1 ، 2 ، 3 }"},{"id":"b","text":"{ −2 ، −1 ، 0 ، 1 ، 2 ، 3 }"},{"id":"c","text":"{ 0 ، 1 ، 2 ، 3 }"},{"id":"d","text":"{ −1 ، 0 ، 1 ، 2 }"}]'::jsonb, 'a', 'من x > −2 نأخذ x ابتداءً من −1 (لأنّ −2 غير مشمول). من 2x ≤ 6 نجد x ≤ 3. إذن −1 ≤ x ≤ 3، والأعداد الصحيحة هي {−1 ، 0 ، 1 ، 2 ، 3}.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

