INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cb586ae-b2fd-53f6-bd68-5c6937b09d6b', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'احلل الجملة:
$$\begin{cases} 3x + 2y = 16 \\ 5x + 2y = 24 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(4 ; 2)"},{"id":"b","text":"(3 ; 3)"},{"id":"c","text":"(5 ; 1)"},{"id":"d","text":"(2 ; 5)"}]'::jsonb, 'a', 'نطرح المعادلة الأولى من الثانية: (5x+2y) − (3x+2y) = 24−16، إذن 2x = 8، x = 4. نعوّض: 3(4) + 2y = 16، 2y = 4، y = 2. الحلّ (4 ; 2). التحقّق: 12+4=16 ✓، 20+4=24 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6672c828-0d0f-597d-859b-009023eda5d1', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'احلل الجملة:
$$\begin{cases} 2x + 3y = 11 \\ x - 3y = 1 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(2 ; 2)"},{"id":"b","text":"(4 ; 1)"},{"id":"c","text":"(5 ; 0)"},{"id":"d","text":"(1 ; 3)"}]'::jsonb, 'b', 'بجمع المعادلتَين: (2x+3y) + (x−3y) = 11+1، إذن 3x = 12، x = 4. نعوّض في الثانية: 4 − 3y = 1، 3y = 3، y = 1. الحلّ (4 ; 1). التحقّق: 8+3=11 ✓، 4−3=1 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19e2b6d3-e5db-594a-87b0-53d0499742a1', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'احلل الجملة:
$$\begin{cases} x + 2y = 9 \\ 3x - 2y = 3 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(4 ; 2)"},{"id":"b","text":"(2 ; 4)"},{"id":"c","text":"(3 ; 3)"},{"id":"d","text":"(5 ; 1)"}]'::jsonb, 'c', 'بجمع المعادلتَين: (x+2y) + (3x−2y) = 9+3، إذن 4x = 12، x = 3. نعوّض في الأولى: 3 + 2y = 9، 2y = 6، y = 3. الحلّ (3 ; 3). التحقّق: 3+6=9 ✓، 9−6=3 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84de1a4f-6204-5ed3-b409-98b15de489c5', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'احلل بطريقة التعويض:
$$\begin{cases} 4x - 3y = 5 \\ 2x + y = 5 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(1 ; 3)"},{"id":"b","text":"(3 ; −1)"},{"id":"c","text":"(2 ; 1)"},{"id":"d","text":"(0 ; 5)"}]'::jsonb, 'c', 'من المعادلة الثانية: y = 5 − 2x. نعوّض في الأولى: 4x − 3(5−2x) = 5، 4x − 15 + 6x = 5، 10x = 20، x = 2. إذن y = 5 − 4 = 1. الحلّ (2 ; 1). التحقّق: 8−3=5 ✓، 4+1=5 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('074173e5-a5fb-57e5-a01d-d884a549b9fb', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'زاويتان متكاملتان (مجموعهما 180°)، وإحداهما تساوي ثلاثة أمثال الأخرى. ما قيمة الزاوية الأصغر؟', '[{"id":"a","text":"60°"},{"id":"b","text":"30°"},{"id":"c","text":"90°"},{"id":"d","text":"45°"}]'::jsonb, 'd', 'نُسمّي الزاويتَين x وy مع x = 3y. الجملة: x + y = 180 و x = 3y. بالتعويض: 3y + y = 180، 4y = 180، y = 45°. الزاوية الكبرى هي x = 135°. التحقّق: 135 + 45 = 180 ✓، 135 = 3×45 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18e02832-28c9-512d-a7d5-70066a0f6c2a', '93b0884f-f1fa-5677-ba0c-45682a394f86', 'باع بائع تذاكر للكبار بـ 8 دنانير وللصغار بـ 5 دنانير. باع 12 تذكرة مجموعها 72 دينارًا. كم تذكرة للكبار باع؟', '[{"id":"a","text":"6 تذاكر"},{"id":"b","text":"4 تذاكر"},{"id":"c","text":"8 تذاكر"},{"id":"d","text":"3 تذاكر"}]'::jsonb, 'b', 'نُسمّي عدد تذاكر الكبار x وتذاكر الصغار y. الجملة: x + y = 12 و 8x + 5y = 72. من الأولى: y = 12 − x. بالتعويض: 8x + 5(12−x) = 72، 8x + 60 − 5x = 72، 3x = 12، x = 4. إذن 4 تذاكر للكبار و 8 للصغار. التحقّق: 4+8=12 ✓، 8(4)+5(8)=32+40=72 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'e9b1fb37-38ae-5b12-a38b-c6f536ff90a7', 'math', 'تمرين مراجعة: جُمل المعادلتَين بمجهولَين (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d741efb8-605f-5b1d-9111-8e6877639813', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'أيٌّ من الثنائيات التالية هي حلّ الجملة:
$$\begin{cases} 3x - y = 5 \\ x + y = 7 \end{cases}$$', '[{"id":"a","text":"(2 ; 1)"},{"id":"b","text":"(1 ; 6)"},{"id":"c","text":"(4 ; 2)"},{"id":"d","text":"(3 ; 4)"}]'::jsonb, 'd', 'نتحقّق من الثنائية (3 ; 4) في المعادلتَين: المعادلة الأولى: 3(3)−4 = 9−4 = 5 ✓. المعادلة الثانية: 3+4 = 7 ✓. كلتا المعادلتَين محقَّقتان، إذن الحلّ هو (3 ; 4). للتأكّد: نحلّ الجملة بجمع المعادلتَين: (3x−y)+(x+y) = 5+7، إذن 4x = 12، x = 3. نعوّض: 3+y = 7، y = 4.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1aa8e1f-392c-5a10-9f18-c53b4ed30240', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'احلل الجملة بطريقة التعويض:
$$\begin{cases} y = 2x - 1 \\ x + y = 8 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(3 ; 5)"},{"id":"b","text":"(4 ; 4)"},{"id":"c","text":"(2 ; 6)"},{"id":"d","text":"(3 ; 7)"}]'::jsonb, 'a', 'نعوّض y = 2x−1 في المعادلة الثانية: x + (2x−1) = 8، إذن 3x−1 = 8، 3x = 9، x = 3. نحسب y: y = 2(3)−1 = 5. الحلّ (3 ; 5). التحقّق: 5 = 2(3)−1 ✓، 3+5=8 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a321ae6-ca1d-5400-ada2-4901e6421f4f', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'احلل الجملة:
$$\begin{cases} 2x + 3y = 16 \\ 2x - y = 8 \end{cases}$$
ما قيمة y ؟', '[{"id":"a","text":"y = 1"},{"id":"b","text":"y = 4"},{"id":"c","text":"y = 2"},{"id":"d","text":"y = 3"}]'::jsonb, 'c', 'نطرح المعادلة الثانية من الأولى: (2x+3y) − (2x−y) = 16−8، إذن 4y = 8، y = 2. نعوّض في الثانية: 2x−2 = 8، 2x = 10، x = 5. التحقّق: 2(5)+3(2)=10+6=16 ✓، 2(5)−2=8 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee569973-6173-5d85-8bc4-5fc55cae4455', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'احلل الجملة بطريقة التأليف:
$$\begin{cases} 2x + y = 7 \\ x + 2y = 5 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(3 ; 1)"},{"id":"c","text":"(1 ; 2)"},{"id":"d","text":"(4 ; 1)"}]'::jsonb, 'b', 'نضرب المعادلة الأولى في 2: 4x + 2y = 14. نطرح منها المعادلة الثانية: (4x+2y) − (x+2y) = 14−5، إذن 3x = 9، x = 3. نعوّض في المعادلة الأولى: 2(3) + y = 7، y = 1. الحلّ (3 ; 1). التحقّق: 6+1=7 ✓، 3+2=5 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64c15d45-547c-5292-aa95-b0f54942988f', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'في محلّ قرطاسية، ثمن قلم حبر يساوي ثلاثة أمثال ثمن قلم رصاص. اشترى أحمد قلم حبر وقلم رصاص فدفع 8 دنانير. ما ثمن كلٍّ منهما؟', '[{"id":"a","text":"قلم الحبر 5 د، قلم الرصاص 3 د"},{"id":"b","text":"قلم الحبر 4 د، قلم الرصاص 4 د"},{"id":"c","text":"قلم الحبر 6 د، قلم الرصاص 2 د"},{"id":"d","text":"قلم الحبر 3 د، قلم الرصاص 5 د"}]'::jsonb, 'c', 'نُسمّي ثمن قلم الرصاص x وثمن قلم الحبر y. الشرطان: y = 3x (قلم الحبر = ثلاثة أمثال قلم الرصاص) و x + y = 8. بالتعويض: x + 3x = 8، إذن 4x = 8، x = 2. إذن ثمن قلم الرصاص 2 دنانير وثمن قلم الحبر y = 3(2) = 6 دنانير. التحقّق: 2+6=8 ✓، 6=3×2 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('28aa1e42-8121-55b2-81c1-2707775827fa', 'f2e9adfd-e915-5fd1-89e9-3cc24f005f51', 'محيط مستطيل يساوي 34 سم، وطوله يزيد عن عرضه بـ 5 سم. ما مساحة هذا المستطيل؟', '[{"id":"a","text":"66 سم²"},{"id":"b","text":"72 سم²"},{"id":"c","text":"60 سم²"},{"id":"d","text":"56 سم²"}]'::jsonb, 'a', 'نُسمّي الطول l والعرض w. الشرطان: 2(l+w) = 34، إذن l+w = 17، وكذلك l = w+5. بالتعويض: (w+5)+w = 17، 2w = 12، w = 6 سم. إذن l = 6+5 = 11 سم. المساحة = l×w = 11×6 = 66 سم². التحقّق: 2(11+6)=34 ✓، 11−6=5 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('369aa7e7-0b18-5e73-846d-00a0d91b4555', 'e9b1fb37-38ae-5b12-a38b-c6f536ff90a7', 'math', '👑 تحدّي النخبة: جُمل المعادلتَين — مستوى المتفوّقين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac9c290c-85c0-5962-b16e-ac6529697321', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'احلل الجملة بطريقة التأليف:
$$\begin{cases} 3x + 4y = 18 \\ 5x - 2y = 4 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(3 ; 2)"},{"id":"b","text":"(2 ; 3)"},{"id":"c","text":"(4 ; 1)"},{"id":"d","text":"(1 ; 4)"}]'::jsonb, 'b', 'نضرب المعادلة الثانية في 2: 10x − 4y = 8. نجمع مع الأولى: (3x + 4y) + (10x − 4y) = 18 + 8، إذن 13x = 26، x = 2. نعوّض في الأولى: 3(2) + 4y = 18، 6 + 4y = 18، 4y = 12، y = 3. الحلّ (2 ; 3). التحقّق: 3(2)+4(3)=6+12=18 ✓، 5(2)−2(3)=10−6=4 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0408496-e556-5638-8873-a4a6bed62988', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'مجموع أعمار أب وابنه 52 سنة. عمر الأب يساوي ثلاثة أمثال عمر الابن زائد 4 سنوات. كم عمر الابن؟', '[{"id":"a","text":"10 سنوات"},{"id":"b","text":"14 سنوات"},{"id":"c","text":"12 سنوات"},{"id":"d","text":"16 سنوات"}]'::jsonb, 'c', 'نُسمّي عمر الابن x وعمر الأب y. الجملة: x + y = 52 و y = 3x + 4. بالتعويض: x + (3x + 4) = 52، 4x + 4 = 52، 4x = 48، x = 12. إذن عمر الابن 12 سنة وعمر الأب y = 3(12) + 4 = 40 سنة. التحقّق: 12 + 40 = 52 ✓، 40 = 3×12 + 4 = 40 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e385dcef-58d1-5d1d-93e1-1c5fbe18f8d5', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'مستطيل محيطه 54 cm، وطوله يساوي ضعف عرضه ناقص 3. ما قيمة الطول؟', '[{"id":"a","text":"17 cm"},{"id":"b","text":"10 cm"},{"id":"c","text":"14 cm"},{"id":"d","text":"20 cm"}]'::jsonb, 'a', 'نُسمّي الطول L والعرض W. الجملة: 2(L + W) = 54 إذن L + W = 27، وكذلك L = 2W − 3. بالتعويض: (2W − 3) + W = 27، 3W = 30، W = 10 cm. إذن L = 2(10) − 3 = 17 cm. التحقّق: L + W = 17 + 10 = 27، المحيط = 2×27 = 54 cm ✓، L = 2(10)−3 = 17 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('687fc825-c932-5579-87e1-5a854e981f29', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'سيارتان تنطلقان في نفس الوقت من مدينتَين تفصل بينهما 300 km باتّجاه بعضهما. سرعة السيارة الأولى تفوق سرعة الثانية بـ 20 km/h. تلتقيان بعد 3 ساعات. ما سرعة السيارة الثانية؟', '[{"id":"a","text":"30 km/h"},{"id":"b","text":"50 km/h"},{"id":"c","text":"60 km/h"},{"id":"d","text":"40 km/h"}]'::jsonb, 'd', 'نُسمّي سرعة السيارة الأولى v₁ وسرعة الثانية v₂. الجملة: v₁ + v₂ = 100 (لأنّ 3v₁ + 3v₂ = 300) و v₁ − v₂ = 20. بالجمع: 2v₁ = 120، v₁ = 60 km/h. إذن v₂ = 100 − 60 = 40 km/h. التحقّق: 3(60) + 3(40) = 180 + 120 = 300 km ✓، 60 − 40 = 20 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d31de75-e6b3-57ee-9bdd-645fb8b00cd2', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'احلل الجملة بضرب كلتا المعادلتَين:
$$\begin{cases} 2x + 3y = 16 \\ 3x - 2y = 11 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(5 ; 2)"},{"id":"b","text":"(4 ; 3)"},{"id":"c","text":"(3 ; 4)"},{"id":"d","text":"(2 ; 5)"}]'::jsonb, 'a', 'نضرب المعادلة الأولى في 2: 4x + 6y = 32. نضرب المعادلة الثانية في 3: 9x − 6y = 33. نجمع: (4x + 6y) + (9x − 6y) = 32 + 33، إذن 13x = 65، x = 5. نعوّض في الأولى: 2(5) + 3y = 16، 10 + 3y = 16، 3y = 6، y = 2. الحلّ (5 ; 2). التحقّق: 2(5)+3(2)=10+6=16 ✓، 3(5)−2(2)=15−4=11 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c86fed4-d98d-5d6e-87c2-9154a6945ea4', '369aa7e7-0b18-5e73-846d-00a0d91b4555', 'في فصل دراسيّ، مجموع عدد البنين والبنات 40 تلميذًا. إذا خرج من الفصل 2 بنون وانضمّ إليه 2 بنات، أصبحت نسبة البنين إلى البنات 2 : 3. ما عدد البنات في الأصل؟', '[{"id":"a","text":"16 بنتًا"},{"id":"b","text":"20 بنتًا"},{"id":"c","text":"22 بنتًا"},{"id":"d","text":"18 بنتًا"}]'::jsonb, 'c', 'نُسمّي عدد البنين b وعدد البنات g. الجملة: b + g = 40 و (b − 2)/(g + 2) = 2/3. من الشرط الثاني: 3(b − 2) = 2(g + 2)، إذن 3b − 6 = 2g + 4، أي 3b − 2g = 10. من الأولى: b = 40 − g. نعوّض: 3(40 − g) − 2g = 10، 120 − 3g − 2g = 10، 5g = 110، g = 22. إذن b = 40 − 22 = 18. التحقّق: 18 + 22 = 40 ✓، (18−2)/(22+2) = 16/24 = 2/3 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b5beb3fa-026f-5855-b039-0a90b4473395', 'e9b1fb37-38ae-5b12-a38b-c6f536ff90a7', 'math', 'تمرين تدريبي: جُمل المعادلتَين (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41b9a5da-4e9d-5d8d-ab7a-21ca292f7a7f', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} x + y = 10 \\ x - y = 4 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(7 ; 3)"},{"id":"b","text":"(3 ; 7)"},{"id":"c","text":"(6 ; 4)"},{"id":"d","text":"(5 ; 5)"}]'::jsonb, 'a', 'بجمع المعادلتَين: (x+y) + (x−y) = 10 + 4 → 2x = 14 → x = 7. نعوّض في الأولى: 7 + y = 10 → y = 3. الحلّ (7 ; 3). التحقّق: 7+3=10 ✓، 7−3=4 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('225fa409-a808-5f60-bb79-965b5551c2e1', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} 5x + 4y = 22 \\ 5x - 2y = 4 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(3 ; 2)"},{"id":"c","text":"(4 ; 1)"},{"id":"d","text":"(1 ; 4)"}]'::jsonb, 'a', 'نطرح الثانية من الأولى: (5x+4y) − (5x−2y) = 22 − 4 → 6y = 18 → y = 3. نعوّض في الثانية: 5x − 6 = 4 → 5x = 10 → x = 2. الحلّ (2 ; 3). التحقّق: 10+12=22 ✓، 10−6=4 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3997fe38-e3c1-58e6-9b17-48df8325d664', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل بطريقة التعويض:
$$\begin{cases} y = 2x - 1 \\ 3x + y = 14 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(3 ; 5)"},{"id":"b","text":"(5 ; 9)"},{"id":"c","text":"(2 ; 3)"},{"id":"d","text":"(4 ; 7)"}]'::jsonb, 'a', 'نعوّض y = 2x − 1 في الثانية: 3x + (2x − 1) = 14 → 5x − 1 = 14 → 5x = 15 → x = 3. ثمّ y = 2(3) − 1 = 5. الحلّ (3 ; 5). التحقّق: y=5=2(3)−1 ✓، 3(3)+5=14 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4efc2de5-4561-5d33-96c8-d0137259f75f', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'مجموع عددين 30 والفرق بينهما 8. ما هو العدد الأكبر؟', '[{"id":"a","text":"19"},{"id":"b","text":"11"},{"id":"c","text":"22"},{"id":"d","text":"15"}]'::jsonb, 'a', 'نُسمّي العددين x وy مع x > y. الجملة: x + y = 30 وx − y = 8. بالجمع: 2x = 38 → x = 19. إذن y = 11. العدد الأكبر 19. التحقّق: 19+11=30 ✓، 19−11=8 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50b48c26-99a0-5c11-a7cf-e77b16b8ce0e', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} 2x + 3y = 12 \\ 4x + 6y = 18 \end{cases}$$
ماذا تستنتج؟', '[{"id":"a","text":"لا يوجد حلّ (الجملة مستحيلة)"},{"id":"b","text":"(3 ; 2)"},{"id":"c","text":"ما لا نهاية من الحلول"},{"id":"d","text":"(0 ; 4)"}]'::jsonb, 'a', 'المعادلة الثانية = ضِعف الطرف الأيسر للأولى: 4x + 6y = 2(2x + 3y) = 2 × 12 = 24، لكنّها تساوي 18. وبما أنّ 24 ≠ 18 فالجملة متناقضة ولا حلّ لها (مستقيمان متوازيان غير منطبقين).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d664aae3-820f-56ec-90f6-9250aecfa545', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'اشترى أحمد 3 دفاتر وقلمَين بـ 13 دينارًا، واشترى دفترًا واحدًا وقلمَين بـ 7 دنانير. ما ثمن الدفتر الواحد؟', '[{"id":"a","text":"3 دنانير"},{"id":"b","text":"2 دينار"},{"id":"c","text":"4 دنانير"},{"id":"d","text":"1 دينار"}]'::jsonb, 'a', 'نُسمّي ثمن الدفتر x وثمن القلم y. الجملة: 3x + 2y = 13 وx + 2y = 7. بطرح الثانية من الأولى: 2x = 6 → x = 3. التحقّق: من x + 2y = 7 نجد 2y = 4 فـ y = 2، و3(3)+2(2)=13 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
