INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('715c0c14-c2ec-587a-bdd8-10fb89444410', '8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'ما الفرق الجوهري بين الدالة الخطية والدالة التآلفية؟', '[{"id":"a","text":"الدالة الخطية تمرّ بأيّ نقطة، بينما التآلفية تمرّ بنقطة الأصل فقط"},{"id":"b","text":"الدالة الخطية f(x) = ax تمرّ دائمًا بنقطة الأصل؛ التآلفية f(x) = ax + b لا تمرّ بالأصل إلّا إذا كان b = 0"},{"id":"c","text":"الدالة التآلفية تمرّ دائمًا بنقطة الأصل، بخلاف الخطية"},{"id":"d","text":"الدالتان متطابقتان تمامًا ولا فرق بينهما"}]'::jsonb, 'b', 'الدالة الخطية f(x) = ax تمرّ دائمًا بنقطة الأصل O(0;0) لأنّ f(0) = 0. أمّا الدالة التآلفية f(x) = ax + b فتمرّ بالأصل فقط إذا كان b = 0، وهي حالة خاصّة منها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c1f65db-2e99-579b-b635-6c0f657d0027', '8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'ماذا يُعبّر معامل التوجيه a في الدالة التآلفية f(x) = ax + b؟', '[{"id":"a","text":"يُعبّر عن تراتيب نقطة تقاطع المستقيم مع محور التراتيب"},{"id":"b","text":"يُعبّر عن انحدار المستقيم؛ إذا كان a > 0 فالمستقيم صاعد وإذا كان a < 0 فنازل"},{"id":"c","text":"يُعبّر عن تراتيب نقطة الأصل"},{"id":"d","text":"يُعبّر عن القيمة الثابتة للدالة عند كلّ x"}]'::jsonb, 'b', 'معامل التوجيه a يحدّد انحدار المستقيم: a > 0 يعني مستقيمًا صاعدًا، a < 0 يعني مستقيمًا نازلًا، وكلّما كانت |a| أكبر كان المستقيم أكثر انحدارًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15331d4e-37e6-5291-ab06-85dcd16e0331', '8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'ما قيمة القطع b في الدالة f(x) = ax + b، وأين يظهر بيانيًّا؟', '[{"id":"a","text":"b = f(1)، وهو تراتيب النقطة التي يقطع فيها المستقيم محور الفواصل"},{"id":"b","text":"b = f(0)، وهو تراتيب النقطة التي يقطع فيها المستقيم محور التراتيب"},{"id":"c","text":"b هو ميل المستقيم ولا علاقة له بمحور التراتيب"},{"id":"d","text":"b = f(a)، ولا يظهر بيانيًّا بشكل مباشر"}]'::jsonb, 'b', 'القطع b = f(0) = a×0 + b = b. بيانيًّا هو تراتيب النقطة التي يقطع فيها المستقيم محور التراتيب (المحور العمودي)، أي النقطة (0 ; b).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fcbb23d5-7e21-57df-98b8-2e3f8c777bdb', '8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'ما التمثيل البياني لكلٍّ من الدالة الخطية والدالة التآلفية؟', '[{"id":"a","text":"منحنى من الدرجة الثانية (قطع مكافئ)"},{"id":"b","text":"دائرة مركزها نقطة الأصل"},{"id":"c","text":"مستقيم"},{"id":"d","text":"متقطّع من النقاط المتفرّقة"}]'::jsonb, 'c', 'التمثيل البياني لكلٍّ من الدالة الخطية (f(x) = ax) والدالة التآلفية (f(x) = ax + b) هو مستقيم. لرسمه يكفي حساب نقطتَين وصلهما بمستقيم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d44b940-4d60-5203-831b-7cc08540267c', '8b454cf8-3e90-5659-95d3-6b1d47907ff2', 'كيف نحسب معامل التوجيه a إذا كان المستقيم يمرّ بنقطتَين A(x₁ ; y₁) وB(x₂ ; y₂)؟', '[{"id":"a","text":"a = (x₂ − x₁) / (y₂ − y₁)"},{"id":"b","text":"a = (y₂ − y₁) / (x₂ − x₁)"},{"id":"c","text":"a = (y₂ + y₁) / (x₂ + x₁)"},{"id":"d","text":"a = (x₂ × y₁) − (x₁ × y₂)"}]'::jsonb, 'b', 'معامل التوجيه يُحسب بالصيغة: a = (y₂ − y₁) / (x₂ − x₁)، بشرط أن يكون x₁ ≠ x₂. يمثّل الفرق في التراتيب مقسومًا على الفرق في الفواصل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

