  ('e50af184-82cf-5fed-a75c-5fe103b19bd8', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', 'تمرين مراجعة: الدوال الخطية والتآلفية (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
