INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('470b2abb-e2d1-5315-b0af-5a59725ad1e9', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة التآلفية f تُعرَّف بـ f(x) = 3x − 5. ما قيمة f(4) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"12"},{"id":"c","text":"−2"},{"id":"d","text":"17"}]'::jsonb, 'a', 'f(4) = 3 × 4 − 5 = 12 − 5 = 7. نعوّض x بـ 4 ثمّ نحسب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
