INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb9ef195-275c-578d-8948-feb571f8b0f2', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة الخطية f تُعرَّف بـ f(x) = ax وتحقّق f(4) = 12. ما هو تعبير f؟', '[{"id":"a","text":"f(x) = 3x"},{"id":"b","text":"f(x) = 4x"},{"id":"c","text":"f(x) = 8x"},{"id":"d","text":"f(x) = 48x"}]'::jsonb, 'a', 'من f(4) = 12 نجد a = 12 ÷ 4 = 3. إذن f(x) = 3x. التحقّق: f(4) = 3 × 4 = 12 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b51d59e1-2dd4-58e6-bfcb-0c018e325a4f', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'بيان دالة تآلفية يمرّ بالنقطتَين A(0 ; 3) وB(2 ; 7). ما هو تعبيرها؟', '[{"id":"a","text":"f(x) = 2x + 3"},{"id":"b","text":"f(x) = 3x + 2"},{"id":"c","text":"f(x) = 2x − 3"},{"id":"d","text":"f(x) = 4x + 3"}]'::jsonb, 'a', 'معامل التوجيه a = (7 − 3) ÷ (2 − 0) = 4 ÷ 2 = 2. الترتيب في المبدأ b = f(0) = 3. إذن f(x) = 2x + 3.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d01578db-cdb6-5429-948d-0af4b218293a', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة f تُعرَّف بـ f(x) = −2x + 8. ما قيمة x حين f(x) = 0 (الصفر)؟', '[{"id":"a","text":"4"},{"id":"b","text":"−4"},{"id":"c","text":"8"},{"id":"d","text":"16"}]'::jsonb, 'a', 'نحلّ −2x + 8 = 0 → −2x = −8 → x = 4. هذه هي قيمة x التي ينقطع عندها البيان مع محور الفواصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac721d06-1e23-5b71-a645-d75539ffa1a3', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'أيّ مستقيم من المستقيمات التالية نازل (تناقصي)؟', '[{"id":"a","text":"f(x) = −0.5x + 1"},{"id":"b","text":"f(x) = 2x − 3"},{"id":"c","text":"f(x) = x"},{"id":"d","text":"f(x) = 4x + 2"}]'::jsonb, 'a', 'المستقيم نازل (تناقصي) إذا كان معامل التوجيه a سالبًا. الوحيد ذو المعامل السالب هو f(x) = −0.5x + 1 حيث a = −0.5 < 0.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d210975c-8a82-5ce6-a253-c3d8df7a2dec', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'مستقيمان: f(x) = 3x − 1 وg(x) = x + 5. ما إحداثيّا نقطة تقاطعهما؟', '[{"id":"a","text":"(3 ; 8)"},{"id":"b","text":"(2 ; 5)"},{"id":"c","text":"(3 ; 5)"},{"id":"d","text":"(1 ; 6)"}]'::jsonb, 'a', 'نحلّ 3x − 1 = x + 5 → 2x = 6 → x = 3. الصورة: f(3) = 3(3) − 1 = 8. نقطة التقاطع (3 ; 8). التحقّق: g(3) = 3 + 5 = 8 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7e3372ce-3987-501b-a6e5-211167b35fb0', '02eb650b-9f63-52d8-af00-acd3d01b6c4d', 'math', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c597fe7-dcfc-5ea3-b44a-54b74777d2f3', '7e3372ce-3987-501b-a6e5-211167b35fb0', 'في دراسة إحصائية لعلامات تلاميذ فصل، ما الذي يُمثّل الميزة (caractère)؟', '[{"id":"a","text":"مجموعة التلاميذ الثلاثين في الفصل"},{"id":"b","text":"العلامة (من 0 إلى 20) التي نقيسها أو نلاحظها"},{"id":"c","text":"التكرار الكلّي لجميع القيم"},{"id":"d","text":"المعدّل الحسابي للعلامات"}]'::jsonb, 'b', 'الميزة هي الخاصيّة التي نقيسها أو نلاحظها في الدراسة، كالعلامة أو الطول أو عدد الإخوة. أمّا مجموعة الأفراد المدروسة فهي المجتمع (population).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('794c2db5-1f26-5c80-a027-d4d467d1897c', '7e3372ce-3987-501b-a6e5-211167b35fb0', 'ما الفرق بين التكرار (effectif) والتواتر (fréquence) لقيمة معيّنة؟', '[{"id":"a","text":"التكرار والتواتر مصطلحان مترادفان يعنيان الشيء نفسه"},{"id":"b","text":"التكرار هو عدد مرّات ظهور القيمة؛ التواتر هو نسبتها من التكرار الكلّي (nᵢ / n)"},{"id":"c","text":"التواتر هو عدد مرّات ظهور القيمة؛ التكرار هو نسبتها المئوية"},{"id":"d","text":"التكرار هو مجموع التواترات الكلّية"}]'::jsonb, 'b', 'التكرار nᵢ هو عدد مرّات ظهور القيمة. التواتر fᵢ = nᵢ / n هو نسبتها من التكرار الكلّي n، ويتراوح بين 0 و1. مجموع جميع التواترات يساوي 1 دائمًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ad635fa-3037-5dc3-8b0f-75d73fb7da9c', '7e3372ce-3987-501b-a6e5-211167b35fb0', 'ما تعريف المنوال (mode) في الإحصاء؟', '[{"id":"a","text":"القيمة التي تقع في المنتصف حين تُرتَّب القيم تصاعديًّا"},{"id":"b","text":"القيمة التي تتكرّر أكثر من غيرها (أعلى تكرار)"},{"id":"c","text":"مجموع جميع القيم مقسومًا على عددها"},{"id":"d","text":"الفرق بين أكبر قيمة وأصغر قيمة في السلسلة"}]'::jsonb, 'b', 'المنوال هو القيمة ذات التكرار الأعلى في السلسلة الإحصائية. يُقرأ مباشرةً من الجدول دون حساب. قد يكون للسلسلة منوالان إذا اشتركت قيمتان في نفس التكرار الأعلى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fbf5217-2d9e-576b-858b-9be8a7b9ceed', '7e3372ce-3987-501b-a6e5-211167b35fb0', 'ما الصيغة الصحيحة لحساب المعدّل الحسابي لسلسلة إحصائية؟', '[{"id":"a","text":"مجموع جميع القيم فقط، دون قسمة"},{"id":"b","text":"القيمة الوسطى بين أكبر قيمة وأصغر قيمة"},{"id":"c","text":"مجموع (كلّ قيمة مضروبة في تكرارها) مقسومًا على التكرار الكلّي n"},{"id":"d","text":"القيمة الأعلى تكرارًا في السلسلة"}]'::jsonb, 'c', 'المعدّل الحسابي: x̄ = (x₁×n₁ + x₂×n₂ + … + xₖ×nₖ) / n. يتأثّر بالقيم الشاذّة (الكبيرة جدًّا أو الصغيرة جدًّا).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aeb62b5f-4da9-5ed3-af3c-6cd03a64b4b8', '7e3372ce-3987-501b-a6e5-211167b35fb0', 'ما الخاصيّة التي تُميّز الوسيط (médiane) عن المعدّل الحسابي؟', '[{"id":"a","text":"الوسيط يتأثّر بالقيم الشاذّة أكثر من المعدّل"},{"id":"b","text":"الوسيط يساوي دائمًا المعدّل في أيّ سلسلة إحصائية"},{"id":"c","text":"الوسيط لا يتأثّر بالقيم الشاذّة، بخلاف المعدّل"},{"id":"d","text":"الوسيط هو القيمة الأعلى تكرارًا دائمًا"}]'::jsonb, 'c', 'الوسيط هو القيمة التي تقسم السلسلة المرتّبة إلى نصفَين متساويَين، ولا يتأثّر بالقيم الشاذّة. أمّا المعدّل فيتأثّر بها، لذا يُفضَّل الوسيط أحيانًا في التحليل الإحصائي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b6fdc318-4fb8-5cdf-a865-2ffd1468c8b7', '02eb650b-9f63-52d8-af00-acd3d01b6c4d', 'math', 'تمرين: قراءة الجداول وحساب المؤشّرات الإحصائية', 2, 65, 13, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
