  ('7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', '02eb650b-9f63-52d8-af00-acd3d01b6c4d', 'math', '⚔️ زعيم الفصل: تحليل البيانات الإحصائية', 3, 120, 30, 'boss', 'admin', 2)
