INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd5e6dd8-ea99-5933-a9a1-bace14e89610', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'علامات 5 تلاميذ: 8 ، 12 ، 10 ، 14 ، 16. ما هو المعدّل الحسابي؟', '[{"id":"a","text":"12"},{"id":"b","text":"10"},{"id":"c","text":"60"},{"id":"d","text":"13"}]'::jsonb, 'a', 'المعدّل = مجموع القيم ÷ عددها = (8 + 12 + 10 + 14 + 16) ÷ 5 = 60 ÷ 5 = 12. التحقّق: 12 يقع ضمن المدى [8 ، 16] ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
