  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56c67eec-e7cc-51d9-b44b-d10607c08039', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في السلسلة المرتّبة: 4 ، 7 ، 9 ، 11 ، 15 (n = 5). ما هو الوسيط؟', '[{"id":"a","text":"9"},{"id":"b","text":"11"},{"id":"c","text":"9.2"},{"id":"d","text":"8"}]'::jsonb, 'a', 'n = 5 (فردي)، الوسيط هو القيمة ذات الرتبة الوسطى (الثالثة). القيمة الثالثة في السلسلة المرتّبة هي 9.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3924deed-45ce-50c4-bd9c-f2c73b7fedca', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'حصل 4 تلاميذ على العلامة 15، و6 تلاميذ على العلامة 10. ما هو المعدّل الحسابي للمجموعة (n = 10)؟', '[{"id":"a","text":"12"},{"id":"b","text":"12.5"},{"id":"c","text":"11.5"},{"id":"d","text":"25"}]'::jsonb, 'a', 'المجموع = (4 × 15) + (6 × 10) = 60 + 60 = 120. المعدّل = 120 ÷ 10 = 12.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ed0f229-7973-510f-b0d7-2d34cecd6e1a', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في فصل من 40 تلميذًا، يمارس 10 منهم كرة القدم. ما هو التواتر بالمائة لفئة كرة القدم؟', '[{"id":"a","text":"25 %"},{"id":"b","text":"10 %"},{"id":"c","text":"40 %"},{"id":"d","text":"4 %"}]'::jsonb, 'a', 'التواتر = التكرار ÷ التكرار الكلّي = 10 ÷ 40 = 0.25. بالنسبة المئوية: 0.25 × 100 = 25 %.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8bf05e6-1c21-5ad3-b12f-3c2fda68efc0', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في مخطّط دائري لـ 200 شخص، تقابل فئةٌ زاوية قطاع قيسها 72°. كم عدد أفراد هذه الفئة؟', '[{"id":"a","text":"40"},{"id":"b","text":"72"},{"id":"c","text":"36"},{"id":"d","text":"50"}]'::jsonb, 'a', 'التواتر = زاوية القطاع ÷ 360° = 72 ÷ 360 = 0.2. عدد الأفراد = التواتر × الكلّ = 0.2 × 200 = 40.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31033c3d-18db-5262-a31c-24970a5413f3', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'سلسلة من 6 قيم مرتّبة: 3 ، 5 ، 8 ، 8 ، 11 ، 13. أيّ عبارة صحيحة عن الوسيط والمعدّل؟', '[{"id":"a","text":"الوسيط = 8 والمعدّل = 8"},{"id":"b","text":"الوسيط = 8 والمعدّل = 9"},{"id":"c","text":"الوسيط = 9 والمعدّل = 8"},{"id":"d","text":"الوسيط = 6.5 والمعدّل = 8"}]'::jsonb, 'a', 'الوسيط (n = 6 زوجي): متوسّط القيمتَين الثالثة والرابعة = (8 + 8) ÷ 2 = 8. المعدّل = (3+5+8+8+11+13) ÷ 6 = 48 ÷ 6 = 8. إذن كلاهما = 8.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

