  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07a1a81e-a0e8-5920-8870-56226919bf79', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث ABC، (MN) ∥ (BC) حيث AM = 4 cm وAB = 12 cm وBC = 9 cm. ما طول MN؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"2 cm"},{"id":"d","text":"3 cm"}]'::jsonb, 'd', 'نسبة التشابه = AM/AB = 4/12 = 1/3. إذن MN = BC × (1/3) = 9 × (1/3) = 3 cm.', 4)
