INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5963e699-a6a5-53b9-99a0-bf6f7f541679', '74145cb9-776f-57a7-a8c3-cacc584944a8', 'في المثلّث القائم ABC حيث الزاوية في B قائمة، أيّ الأضلاع هو الوتر ولماذا؟', '[{"id":"a","text":"[AB]، لأنّه أحد الضلعين القائمَين"},{"id":"b","text":"[BC]، لأنّه الضلع الأطول"},{"id":"c","text":"[AC]، لأنّه الضلع المقابل للزاوية القائمة"},{"id":"d","text":"لا يوجد وتر في هذا المثلّث"}]'::jsonb, 'c', 'الوتر هو الضلع المقابل للزاوية القائمة. بما أنّ الزاوية القائمة في B، فالضلع المقابل لها هو [AC]، وهو دائمًا أطول الأضلاع الثلاثة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20f866fe-cb8e-5d64-a234-7f481b7a6151', '74145cb9-776f-57a7-a8c3-cacc584944a8', 'تنصّ نظرية فيثاغورس في المثلّث القائم ABC (الزاوية القائمة في B) على أنّ:', '[{"id":"a","text":"AC = AB + BC"},{"id":"b","text":"AB² + AC² = BC²"},{"id":"c","text":"AC² = AB² + BC²"},{"id":"d","text":"AB² = AC² − BC²"}]'::jsonb, 'c', 'نظرية فيثاغورس: مربّع الوتر = مجموع مربّعَي الضلعَين القائمَين. الوتر هو AC إذن: AC² = AB² + BC².', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('255f2f76-e91f-572d-91a4-8798449d32b3', '74145cb9-776f-57a7-a8c3-cacc584944a8', 'في مثلّث قائم في B، الزاوية في A تساوي x. ماذا تساوي النسبة المثلّثية cos(x)؟', '[{"id":"a","text":"الضلع المقابل لـ x مقسومًا على الوتر"},{"id":"b","text":"الوتر مقسومًا على الضلع المجاور لـ x"},{"id":"c","text":"الضلع المقابل لـ x مقسومًا على الضلع المجاور"},{"id":"d","text":"الضلع المجاور لـ x مقسومًا على الوتر"}]'::jsonb, 'd', 'جيب التمام (cos): الضلع المجاور ÷ الوتر. للتذكّر: جتا = مجاور/وتر؛ جا = مقابل/وتر؛ ظا = مقابل/مجاور.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83373ac3-17cf-516c-bdc4-11c678fd2237', '74145cb9-776f-57a7-a8c3-cacc584944a8', 'ما قيمة tan(45°) ؟', '[{"id":"a","text":"√3"},{"id":"b","text":"1"},{"id":"c","text":"√3/3"},{"id":"d","text":"√2/2"}]'::jsonb, 'b', 'من جدول القيم المشهورة: tan(45°) = 1. وهذا منطقي لأنّ عند 45° الضلع المقابل يساوي الضلع المجاور في المثلّث القائم متساوي الساقين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b308967-00fd-590a-b9fb-90c407ec878c', '74145cb9-776f-57a7-a8c3-cacc584944a8', 'العلاقة sin²(x) + cos²(x) = 1 تنبثق مباشرةً من:', '[{"id":"a","text":"نظرية طاليس المطبّقة على الزوايا الحادّة"},{"id":"b","text":"نظرية فيثاغورس مطبَّقة على مثلّث قائم وتره يساوي 1"},{"id":"c","text":"مجموع زوايا المثلّث = 180°"},{"id":"d","text":"تعريف الدائرة المثلّثية فقط دون فيثاغورس"}]'::jsonb, 'b', 'إذا كان الوتر = 1، فالمقابل = sin(x) والمجاور = cos(x). بتطبيق فيثاغورس: مقابل² + مجاور² = وتر²، أي sin²(x) + cos²(x) = 1²= 1.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

