INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b891195-d929-59b5-9f39-4d2a0a8a7b58', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'في المثلث ABC القائم في B، AB = 3 cm وBC = 4 cm. ما طول الوتر AC؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"√7 cm"},{"id":"d","text":"25 cm"}]'::jsonb, 'a', 'بتطبيق فيثاغورس: AC² = AB² + BC² = 9 + 16 = 25، إذن AC = √25 = 5 cm. هذه هي الثلاثية الفيثاغورية (3، 4، 5).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('570ce82b-9da4-5ec0-9ba0-f0d30d87db7c', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'ما قيمة جا(45°)؟', '[{"id":"a","text":"√2/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√3/2"},{"id":"d","text":"1"}]'::jsonb, 'a', 'جا(45°) = sin(45°) = √2/2 ≈ 0.707. في مثلث متساوي الساقين بزاوية قائمة، الضلع المقابل يساوي الوتر ÷ √2.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2614767c-0baf-5c37-8612-11f6ae986ff8', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'ما قيمة جتا(60°)؟', '[{"id":"a","text":"√3/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√2/2"},{"id":"d","text":"√3"}]'::jsonb, 'b', 'جتا(60°) = cos(60°) = 1/2. وبالمقابل جتا(30°) = √3/2؛ لاحظ أنّ جتا(30°) = جا(60°) والعكس بالعكس.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6c48408-d32a-5952-bef9-58ac1091a3bb', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'ما قيمة ظا(30°)؟', '[{"id":"a","text":"1"},{"id":"b","text":"√3"},{"id":"c","text":"√3/3"},{"id":"d","text":"1/2"}]'::jsonb, 'c', 'ظا(30°) = tan(30°) = جا(30°) ÷ جتا(30°) = (1/2) ÷ (√3/2) = 1/√3 = √3/3 (بعد إنطاق المقام).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('51bd4869-6785-596b-a9f8-ec026d774363', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'في المثلث ABC القائم في B، الزاوية A = 30° والوتر AC = 8 cm. ما طول الضلع BC؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"4√3 cm"},{"id":"c","text":"8√3 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'a', 'BC يقابل الزاوية A، إذن جا(A) = BC/AC. نكتب: جا(30°) = BC/8، أي 1/2 = BC/8، فينتج BC = 4 cm.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d20f096e-13e3-5f7c-aa12-9a58fb391cdb', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'أيّ العلاقات التالية صحيحة دائمًا لأيّ زاوية حادّة x؟', '[{"id":"a","text":"جا(x) + جتا(x) = 1"},{"id":"b","text":"جا²(x) + جتا²(x) = 1"},{"id":"c","text":"جا(x) × جتا(x) = 1"},{"id":"d","text":"ظا(x) = جتا(x) ÷ جا(x)"}]'::jsonb, 'b', 'العلاقة المثلثية الأساسية المشتقّة من فيثاغورس: جا²(x) + جتا²(x) = 1. يمكن التحقّق: جا²(30°) + جتا²(30°) = (1/2)² + (√3/2)² = 1/4 + 3/4 = 1.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('80e5983d-9550-5c46-b8da-75359679e18f', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', '⚔️ زعيم الفصل: فيثاغورس والنسب المثلثية — مواجهة الأوتار', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
