INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7756d42f-d6b8-597e-9ac8-561228ef119c', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، AB = 3 cm وAC = 6 cm. ما قيمة الزاوية A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'جتا(A) = المجاور/الوتر = AB/AC = 3/6 = 1/2. ومن جدول القيم المشهورة: جتا(60°) = 1/2، إذن الزاوية A = 60°.', 2)
