INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3be61ed8-9dad-5bd8-96bd-658b7bf37cdb', '80e5983d-9550-5c46-b8da-75359679e18f', 'مثلث أضلاعه 7 cm و24 cm و25 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 7² + 24² = 25²"},{"id":"b","text":"لا، لأنّ 7 + 24 ≠ 25"},{"id":"c","text":"نعم، لأنّ 7 + 24 > 25"},{"id":"d","text":"لا، لأنّ 7² + 24² ≠ 25²"}]'::jsonb, 'a', 'نحسب: 7² + 24² = 49 + 576 = 625 = 25². بما أنّ مجموع مربّعي الضلعين الأصغرين يساوي مربّع الضلع الأكبر، فالمثلث قائم الزاوية بعكس فيثاغورس.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e58b813c-6f19-5dc1-8956-6fd01e9b3f54', '80e5983d-9550-5c46-b8da-75359679e18f', 'في مثلث قائم، الزاوية A حادّة وظا(A) = √3. ما قيمة الزاوية A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'من جدول القيم المشهورة: ظا(60°) = √3. إذن الزاوية A = 60°. تذكّر: ظا(30°) = √3/3 وظا(45°) = 1.', 4)
