  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c2b81dea-f750-5535-8070-b2ff6fb7cc6e', '80e5983d-9550-5c46-b8da-75359679e18f', 'إذا كانت جا(x) = √3/2 وكانت x زاوية حادّة، فما قيمة جتا(x)؟', '[{"id":"a","text":"√3/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√2/2"},{"id":"d","text":"1"}]'::jsonb, 'b', 'جا(x) = √3/2 يعني x = 60°. إذن جتا(60°) = 1/2. يمكن التحقّق باستعمال العلاقة الأساسية: جتا²(x) = 1 − جا²(x) = 1 − 3/4 = 1/4، فجتا(x) = 1/2.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbd6cbe7-2f11-59c5-b6be-0ba8bd2f84f3', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، الزاوية C = 45° والوتر AC = 10 cm. ما طول الضلع BC؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"5√2 cm"},{"id":"c","text":"10√2 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'b', 'جتا(C) = BC/AC، إذن جتا(45°) = BC/10، أي √2/2 = BC/10، فينتج BC = 10 × √2/2 = 5√2 cm ≈ 7.07 cm.', 6)
