INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfde8594-7f9d-5279-9ae7-07c51d52d0a6', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AB = 8 cm وBC = 6 cm. ما طول الوتر AC؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"14 cm"},{"id":"c","text":"√14 cm"},{"id":"d","text":"100 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: AC² = AB² + BC² = 64 + 36 = 100، إذن AC = √100 = 10 cm. هذه الثلاثية المشهورة (6، 8، 10) من مضاعفات (3، 4، 5).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9889a97c-458b-557a-95f0-512fc6ded20b', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AC = 13 cm وAB = 5 cm. ما طول BC؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"√194 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'a', 'AC هو الوتر. بفيثاغورس: AC² = AB² + BC² → 13² = 5² + BC² → 169 = 25 + BC² → BC² = 144 → BC = 12 cm. الثلاثية (5، 12، 13).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c986e021-1f47-5951-a459-a127caba0567', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'مثلث أضلاعه 9 cm و12 cm و15 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 9² + 12² = 15²"},{"id":"b","text":"لا، لأنّ 9 + 12 ≠ 15"},{"id":"c","text":"نعم، لأنّ 9 + 12 > 15"},{"id":"d","text":"لا، لأنّ 9² + 12² ≠ 15²"}]'::jsonb, 'a', 'نحسب: 9² + 12² = 81 + 144 = 225 = 15². بما أنّ مجموع مربّعي الضلعين الأصغرين يساوي مربّع الأكبر، فالمثلث قائم بعكس فيثاغورس.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68dd2292-5551-5e45-8852-262481a36870', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة A تحقّق جا(A) = 1/2. ما قيمة A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'من جدول القيم المشهورة: جا(30°) = 1/2. إذن A = 30°. تذكّر: جا(45°) = √2/2 وجا(60°) = √3/2.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ea0a760-4e4a-5e7d-b9d5-17a7ac759091', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، الزاوية A = 30° والوتر AC = 12 cm. ما طول الضلع BC (المقابل للزاوية A)؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"6√3 cm"},{"id":"c","text":"12√3 cm"},{"id":"d","text":"4 cm"}]'::jsonb, 'a', 'جا(A) = المقابل/الوتر = BC/AC. إذن جا(30°) = BC/12، أي 1/2 = BC/12، فينتج BC = 12 × 1/2 = 6 cm.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ed6a19c-2f76-549e-829a-3e952ee94469', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة x تحقّق جتا(x) = √2/2. ما قيمة جا(x) ؟', '[{"id":"a","text":"√2/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√3/2"},{"id":"d","text":"1"}]'::jsonb, 'a', 'جتا(x) = √2/2 يعني x = 45°. إذن جا(45°) = √2/2. التحقّق بالعلاقة الأساسية: جا²(x) + جتا²(x) = 1/2 + 1/2 = 1 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b772b8d9-c085-5955-8cc6-af66b54cf2c8', '069523c8-c228-5326-bbc1-31ad25257541', 'math', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
