INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30ce1ea7-3aef-513b-85ac-192597814cff', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'ما الفرق الجوهري بين الزاوية المركزية والزاوية المحيطية في الدائرة؟', '[{"id":"a","text":"الزاوية المركزية رأسها على الدائرة؛ والمحيطية رأسها في المركز"},{"id":"b","text":"الزاوية المركزية رأسها مركز الدائرة وضلعاها نصفا قطرين؛ والمحيطية رأسها نقطة على الدائرة وضلعاها وتران"},{"id":"c","text":"لا فرق؛ كلتاهما تساوي قيس القوس ذاته"},{"id":"d","text":"الزاوية المحيطية دائمًا أكبر من المركزية لنفس القوس"}]'::jsonb, 'b', 'الزاوية المركزية: رأسها المركز O وضلعاها نصفا قطرَين. الزاوية المحيطية: رأسها نقطة على الدائرة وضلعاها وتران. هذا هو التمييز التعريفي بينهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7852d3bf-c345-5dbf-8cbe-3ebbb25e8a3b', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'ما العلاقة الرياضية بين الزاوية المحيطية والزاوية المركزية المقابلتَين لنفس القوس؟', '[{"id":"a","text":"الزاوية المحيطية = الزاوية المركزية"},{"id":"b","text":"الزاوية المحيطية = 2 × الزاوية المركزية"},{"id":"c","text":"الزاوية المحيطية = نصف الزاوية المركزية"},{"id":"d","text":"الزاوية المحيطية + الزاوية المركزية = 180°"}]'::jsonb, 'c', 'النظرية الكبرى: الزاوية المحيطية = (1/2) × الزاوية المركزية المقابلة لنفس القوس. وبالتالي الزاوية المركزية = 2 × الزاوية المحيطية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63768b0e-3a26-5eea-ae59-a034ac1fc46f', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'في دائرة مركزها O، إذا كانت الزاوية المركزية AOB = 140°، فما قيمة الزاوية المحيطية ACB (حيث C على القوس الكبير)؟', '[{"id":"a","text":"280°"},{"id":"b","text":"140°"},{"id":"c","text":"70°"},{"id":"d","text":"40°"}]'::jsonb, 'c', 'الزاوية المحيطية = نصف الزاوية المركزية لنفس القوس. إذن ACB = 140° ÷ 2 = 70°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b3d3699-c897-5da7-9806-c38b02fac914', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'إذا كانت [AC] قطرًا في دائرة وB نقطة على الدائرة غير A وC، فما قيمة الزاوية ABC وما مبرّرها؟', '[{"id":"a","text":"60°؛ لأنّ المثلّث ABC متساوي الأضلاع"},{"id":"b","text":"45°؛ لأنّ B منتصف القوس"},{"id":"c","text":"180°؛ لأنّ A وB وC على خطّ واحد"},{"id":"d","text":"90°؛ لأنّ الزاوية المحيطية المحصورة في نصف دائرة قائمة دائمًا"}]'::jsonb, 'd', 'القطر AC يقابل زاوية مركزية = 180°. إذن الزاوية المحيطية ABC = 180° ÷ 2 = 90°. «الزاوية المحيطية المحصورة في نصف دائرة قائمة» — جملة يجب حفظها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b57e4cb3-047d-5c19-98c4-e8a04074c9ae', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'إذا كانت C وD نقطتَين على دائرة من نفس الجهة بالنسبة للوتر [AB]، فما العلاقة بين الزاويتَين ACB وADB؟', '[{"id":"a","text":"ACB + ADB = 360°"},{"id":"b","text":"ACB = ADB (الزاويتان متقايستان)"},{"id":"c","text":"ACB = 2 × ADB"},{"id":"d","text":"لا علاقة تربطهما"}]'::jsonb, 'b', 'الزوايا المحيطية التي تحصر نفس القوس وتنتمي إلى نفس الجهة تكون متقايسة. كلتاهما تساوي نصف الزاوية المركزية المقابلة لذلك القوس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('93dfdc12-2b72-5865-99a2-cbfa62c0ded0', '069523c8-c228-5326-bbc1-31ad25257541', 'math', 'تمرين: الزاوية المركزية والزاوية المحيطية', 2, 65, 13, 'practice', 'admin', 1)
