  ('1723a195-8a7d-58a9-aca8-4e9271a11138', '069523c8-c228-5326-bbc1-31ad25257541', 'math', 'تمرين مراجعة: الزوايا في الدائرة (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
