INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac6fd8cf-2009-5ca5-a70d-28bcebcf296b', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاوية المحيطية MPN = 35°. ما قيمة الزاوية المركزية MON المقابلة لنفس القوس؟', '[{"id":"a","text":"70°"},{"id":"b","text":"35°"},{"id":"c","text":"17.5°"},{"id":"d","text":"145°"}]'::jsonb, 'a', 'الزاوية المركزية = ضعف الزاوية المحيطية المقابلة لنفس القوس. MON = 2 × 35° = 70°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('253fac3f-1b6c-57d8-83fc-3ea1177d0df2', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، [AB] قطر وC نقطة على الدائرة. إذا كانت الزاوية CAB = 40°، ما قيمة الزاوية ABC؟', '[{"id":"a","text":"50°"},{"id":"b","text":"40°"},{"id":"c","text":"90°"},{"id":"d","text":"140°"}]'::jsonb, 'a', 'بما أنّ [AB] قطر، فالزاوية ACB = 90° (زاوية محيطية تحصر نصف دائرة). في المثلث ABC: ABC = 180° − 90° − 40° = 50°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b903fee-9e5b-5af1-a92d-255687213b58', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، زاويتان محيطيتان ACB وADB تحصران القوس نفسه AB من الجهة نفسها. إذا كانت ACB = 47°، فما قيمة ADB؟', '[{"id":"a","text":"47°"},{"id":"b","text":"94°"},{"id":"c","text":"23.5°"},{"id":"d","text":"133°"}]'::jsonb, 'a', 'كلّ زاويتَين محيطيتَين تحصران القوس نفسه من الجهة نفسها متساويتان. إذن ADB = ACB = 47°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a26d1a7-cbef-59b4-9541-8d3f57bb2cfa', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 120°. ما قيس القوس الصغير AB؟', '[{"id":"a","text":"120°"},{"id":"b","text":"60°"},{"id":"c","text":"240°"},{"id":"d","text":"30°"}]'::jsonb, 'a', 'قيس الزاوية المركزية يساوي قيس قوسها المقابل. إذن قيس القوس الصغير AB = 120°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b6092af-fe1c-59f9-92fa-22d6183c0df4', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاوية المحيطية ACB = 54°. ما قيس القوس الكبير AB (الذي لا يحوي C)؟', '[{"id":"a","text":"252°"},{"id":"b","text":"108°"},{"id":"c","text":"126°"},{"id":"d","text":"306°"}]'::jsonb, 'a', 'القوس الصغير AB المقابل للزاوية المحيطية = 2 × 54° = 108°. القوس الكبير = 360° − 108° = 252°.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c454f3ce-b206-527f-8ceb-4894b5ed3dc8', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
