INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec21e283-d27c-526f-a47d-0389f7739de8', 'c454f3ce-b206-527f-8ceb-4894b5ed3dc8', 'للشعاع AB أربع خصائص هندسية. أيّ الخيارات التالية يذكر هذه الخصائص الأربع بشكل صحيح؟', '[{"id":"a","text":"المنشأ، الاتجاه، المنحى، الطول (النورم)"},{"id":"b","text":"المنشأ، الاتجاه، المنحى، المساحة"},{"id":"c","text":"الطول، العرض، الارتفاع، الزاوية"},{"id":"d","text":"الاتجاه، الطول، المنشأ، درجة الميل"}]'::jsonb, 'a', 'خصائص الشعاع الأربع هي: المنشأ (نقطة الانطلاق)، الاتجاه (المستقيم الحامل)، المنحى (من A نحو B)، والطول (نورم الشعاع ‖AB‖). المساحة أو درجة الميل ليستا خاصيّتَين للشعاع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5802beec-94bf-55fd-b4ad-52932314138d', 'c454f3ce-b206-527f-8ceb-4894b5ed3dc8', 'متى يكون الشعاعان AB و CD متساويَين؟', '[{"id":"a","text":"حين يكون لهما نفس المنشأ فقط"},{"id":"b","text":"حين يكون لهما نفس الطول فحسب"},{"id":"c","text":"حين يكون لهما نفس الاتجاه ونفس المنحى ونفس الطول"},{"id":"d","text":"حين يقعان على نفس المستقيم"}]'::jsonb, 'c', 'تساوي الشعاعين يشترط ثلاثة أمور معًا: نفس الاتجاه، نفس المنحى، ونفس الطول. المنشأ قد يختلف — في متوازي الأضلاع AB = DC رغم اختلاف نقطتَي الانطلاق.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73291e4a-ee50-5da4-9dc9-32ae176a012a', 'c454f3ce-b206-527f-8ceb-4894b5ed3dc8', 'تنصّ علاقة شال (Chasles) على أنّ: AB + BC = ?', '[{"id":"a","text":"BA"},{"id":"b","text":"AC"},{"id":"c","text":"CA"},{"id":"d","text":"صفر دائمًا"}]'::jsonb, 'b', 'علاقة شال: AB + BC = AC. طرف الشعاع الأوّل (B) يتطابق مع منشأ الشعاع الثاني (B) فيُلغى وينتج مباشرةً الشعاع AC من A إلى C.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('745bc624-63e6-5af2-9302-20dd9d4eb610', 'c454f3ce-b206-527f-8ceb-4894b5ed3dc8', 'الانسحاب ذو الشعاع u ينقل النقطة M إلى M''. أيّ العبارات التالية وصف صحيح لهذا التحويل؟', '[{"id":"a","text":"MM'' = u، ويُغيّر الأطوال والزوايا"},{"id":"b","text":"MM'' = u، ويحفظ الأطوال والزوايا، وصورة أيّ مستقيم مستقيمٌ موازٍ له"},{"id":"c","text":"يضاعف المسافة بمعامل ثابت"},{"id":"d","text":"يُبقي النقطة في مكانها إذا كان الشعاع صفريًّا فقط"}]'::jsonb, 'b', 'الانسحاب: MM'' = u. خصائصه: يحفظ الأطوال والزوايا والأشكال (يُبقي الشكل دون تغيير حجمه)، وصورة أيّ مستقيم هي مستقيم مواٍز له.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16d7761e-4897-5d9d-b8f6-9260b35a9cd9', 'c454f3ce-b206-527f-8ceb-4894b5ed3dc8', 'إذا كان ABCD متوازي أضلاع، فأيّ المعادلات التالية صحيحة بين الأشعّة؟', '[{"id":"a","text":"AB = CD"},{"id":"b","text":"AB = DC"},{"id":"c","text":"AB = −BC"},{"id":"d","text":"AB = BD"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: AB = DC (لا CD!). الضلعان المتوازيان AB وDC لهما نفس الاتجاه ونفس المنحى ونفس الطول. أمّا AB = CD فيعكس المنحى، وهو خطأ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d5ed3185-e602-5baa-a49f-a68b1191ac7f', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', 'تمرين: الأشعّة وعلاقة شال', 2, 65, 13, 'practice', 'admin', 1)
