INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4642479-04db-524b-8493-07275599ab8a', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج $\overrightarrow{AB} + \overrightarrow{BC}$ وفق علاقة شال؟', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$\\overrightarrow{CA}$"},{"id":"c","text":"$\\overrightarrow{BA}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'a', 'علاقة شال تنصّ على: $\overrightarrow{AB} + \overrightarrow{BC} = \overrightarrow{AC}$. نتتبّع الحروف: نبدأ من A وننتهي في C مرورًا بـ B.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9c8d407-2396-539e-864e-40d48e430134', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج $\overrightarrow{AB} + \overrightarrow{BA}$؟', '[{"id":"a","text":"$2\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{AA}$"},{"id":"c","text":"$\\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{AB}$"}]'::jsonb, 'c', 'بتطبيق شال: $\overrightarrow{AB} + \overrightarrow{BA} = \overrightarrow{AA} = \overrightarrow{0}$. أي أنّ $\overrightarrow{BA} = -\overrightarrow{AB}$ وهو الشعاع المعاكس.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d31b6e9-d3c9-5b12-8a64-9b080894d622', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ABCD متوازي أضلاع. أيّ من المساواات التالية صحيحة؟', '[{"id":"a","text":"$\\overrightarrow{AB} = \\overrightarrow{CD}$"},{"id":"b","text":"$\\overrightarrow{AB} = \\overrightarrow{DC}$"},{"id":"c","text":"$\\overrightarrow{AB} = \\overrightarrow{CB}$"},{"id":"d","text":"$\\overrightarrow{AD} = \\overrightarrow{CB}$"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: الضلعان AB وDC متوازيان ومتساويان في الطول ونفس المنحى، إذن $\overrightarrow{AB} = \overrightarrow{DC}$. انتبه: $\overrightarrow{CD}$ معاكس المنحى لـ $\overrightarrow{DC}$.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa1aa792-ea33-5d2e-b34f-db59004f7bef', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'M نقطة في المستوي. صورتها بالانسحاب ذي الشعاع $\overrightarrow{AB}$ هي النقطة M'' التي تحقّق:', '[{"id":"a","text":"$\\overrightarrow{M''M} = \\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{MM''} = \\overrightarrow{AB}$"},{"id":"c","text":"$MM'' = 0$"},{"id":"d","text":"$M'' = M$"}]'::jsonb, 'b', 'الانسحاب ذو الشعاع $\overrightarrow{AB}$ ينقل كلّ نقطة M إلى M'' بحيث $\overrightarrow{MM''} = \overrightarrow{AB}$. المنشأ هو M والطرف هو M''.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59416d62-ddd9-569b-93cf-947e49de5bbb', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج $\overrightarrow{AB} + \overrightarrow{BC} + \overrightarrow{CD}$؟', '[{"id":"a","text":"$\\overrightarrow{BD}$"},{"id":"b","text":"$\\overrightarrow{AC}$"},{"id":"c","text":"$\\overrightarrow{AD}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'c', 'نطبّق شال تدريجيًا: $\overrightarrow{AB} + \overrightarrow{BC} = \overrightarrow{AC}$، ثمّ $\overrightarrow{AC} + \overrightarrow{CD} = \overrightarrow{AD}$.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ffa1eaa-9c2c-592c-8187-09ebaa1a178d', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ABCD متوازي أضلاع مركزه O. ما ناتج $\overrightarrow{OA} + \overrightarrow{OC}$؟', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$2\\overrightarrow{OC}$"},{"id":"c","text":"$\\overrightarrow{OB}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'd', 'O هو منتصف [AC] في متوازي الأضلاع، إذن $\overrightarrow{OA} = -\overrightarrow{OC}$، ومنه $\overrightarrow{OA} + \overrightarrow{OC} = \overrightarrow{0}$.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('93d7ec3c-499d-5401-afbd-44d801bd6165', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '⚔️ زعيم الفصل: الأشعّة والانسحاب — المعركة الكبرى', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
