INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4609e772-5f83-5574-8c5e-b07651940b89', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'ABCD متوازي أضلاع. بسّط التعبير: $\overrightarrow{CA} + \overrightarrow{AB} + \overrightarrow{BD}$', '[{"id":"a","text":"$\\overrightarrow{CD}$"},{"id":"b","text":"$\\overrightarrow{AD}$"},{"id":"c","text":"$\\overrightarrow{CB}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'a', 'نطبّق شال تدريجيًا: $\overrightarrow{CA} + \overrightarrow{AB} = \overrightarrow{CB}$، ثمّ $\overrightarrow{CB} + \overrightarrow{BD} = \overrightarrow{CD}$. النتيجة هي $\overrightarrow{CD}$.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1029d23d-c758-50bc-b5ba-adcdadbe99a5', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'A وB وC ثلاث نقاط بحيث $\overrightarrow{AB} + \overrightarrow{CA} = \overrightarrow{u}$. ما هو $\overrightarrow{u}$؟', '[{"id":"a","text":"$\\overrightarrow{CB}$"},{"id":"b","text":"$\\overrightarrow{BC}$"},{"id":"c","text":"$\\overrightarrow{AC}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'a', 'نرتّب الشعاعين: $\overrightarrow{CA} + \overrightarrow{AB}$ (الجمع تبديلي)، فبتطبيق شال: $\overrightarrow{CA} + \overrightarrow{AB} = \overrightarrow{CB}$. إذن $\overrightarrow{u} = \overrightarrow{CB}$.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f58c292-0423-585e-8b48-f312610e77c9', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'صورة المثلث ABC بالانسحاب ذي الشعاع $\overrightarrow{AB}$ هي المثلث A''B''C''. ماذا يساوي $\overrightarrow{AA''}$؟', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$\\overrightarrow{BA}$"},{"id":"c","text":"$\\overrightarrow{AB}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'c', 'في الانسحاب ذي الشعاع $\overrightarrow{AB}$، كلّ نقطة M تنتقل بحيث $\overrightarrow{MM''} = \overrightarrow{AB}$. وبما أنّ A تنتقل إلى A''، فإنّ $\overrightarrow{AA''} = \overrightarrow{AB}$. أمّا الخيارات الأخرى فخاطئة: $\overrightarrow{BA}$ معاكسٌ له، و$\overrightarrow{AC}$ شعاعٌ آخر، و$\overrightarrow{0}$ يعني انعدام الانتقال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1e2bc92-9483-533f-bad1-ea11b4139ae1', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'O هو منتصف [AC] في متوازي الأضلاع ABCD. ما ناتج $\overrightarrow{BA} + \overrightarrow{BC}$؟', '[{"id":"a","text":"$\\overrightarrow{BD}$"},{"id":"b","text":"$2\\overrightarrow{BO}$"},{"id":"c","text":"$\\overrightarrow{AC}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'b', 'لأيّ نقطة O منتصف [AC]: $\overrightarrow{BA} + \overrightarrow{BC} = 2\overrightarrow{BO}$. هذه النتيجة عامّة: مجموع شعاعين من نقطة إلى طرفَي قطعة يساوي ضعف الشعاع من تلك النقطة إلى المنتصف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd7385bc-2ffb-56eb-b657-793013a9961b', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'الشعاع $\overrightarrow{v}$ بحيث $\overrightarrow{AB} + \overrightarrow{v} = \overrightarrow{AC}$. ما هو $\overrightarrow{v}$؟', '[{"id":"a","text":"$\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{BC}$"},{"id":"c","text":"$\\overrightarrow{CA}$"},{"id":"d","text":"$\\overrightarrow{CB}$"}]'::jsonb, 'b', 'من المعادلة: $\overrightarrow{v} = \overrightarrow{AC} - \overrightarrow{AB} = \overrightarrow{AC} + \overrightarrow{BA}$. بشال: $\overrightarrow{BA} + \overrightarrow{AC} = \overrightarrow{BC}$. إذن $\overrightarrow{v} = \overrightarrow{BC}$.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9dd95e83-07c3-5549-80c2-14c2faecbfe6', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'ABCDEF سداسي منتظم مركزه O. ما ناتج $\overrightarrow{AB} + \overrightarrow{CD} + \overrightarrow{EF}$؟', '[{"id":"a","text":"$3\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{AD}$"},{"id":"c","text":"$\\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{AE}$"}]'::jsonb, 'c', 'في السداسي المنتظم: $\overrightarrow{AB} = \overrightarrow{DC}$ لكن $\overrightarrow{CD} = -\overrightarrow{DC}$. بالنظر بالتناظر: $\overrightarrow{AB}$، $\overrightarrow{CD}$، $\overrightarrow{EF}$ ثلاثة أشعّة متساوية الطول ومتوزّعة بزوايا 120° فيما بينها، مجموعها $\overrightarrow{0}$.', 6)
ON CONFLICT (id) DO UPDATE SET
