INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c9d6f98-209e-5468-8a6c-4c87ba7f359c', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'A وB وC وD أربع نقاط. بسّط التعبير التالي: $\overrightarrow{AB} - \overrightarrow{CB} + \overrightarrow{DC} - \overrightarrow{DA}$', '[{"id":"a","text":"$\\overrightarrow{BD}$"},{"id":"b","text":"$2\\overrightarrow{AC}$"},{"id":"c","text":"$\\overrightarrow{AC}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'b', 'نحوّل الطرح إلى جمع: $\overrightarrow{AB} - \overrightarrow{CB} = \overrightarrow{AB} + \overrightarrow{BC}$ وبشال: $= \overrightarrow{AC}$. كذلك $\overrightarrow{DC} - \overrightarrow{DA} = \overrightarrow{DC} + \overrightarrow{AD}$ وبشال ($\overrightarrow{AD} + \overrightarrow{DC}$): $= \overrightarrow{AC}$. إذن المجموع الكلّي $= \overrightarrow{AC} + \overrightarrow{AC} = 2\overrightarrow{AC}$.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d48d4549-5b64-528a-acf7-a8e9a88aa0b2', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'M نقطة في المستوي. صورة M بالانسحاب ذي الشعاع $\overrightarrow{AB}$ هي M''، وصورة M'' بالانسحاب ذي الشعاع $\overrightarrow{BC}$ هي M''''. ما هو $\overrightarrow{MM''''}$؟', '[{"id":"a","text":"$\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{MB}$"},{"id":"c","text":"$\\overrightarrow{AC}$"},{"id":"d","text":"$\\overrightarrow{BC}$"}]'::jsonb, 'c', 'من تعريف الانسحاب: $\overrightarrow{MM''} = \overrightarrow{AB}$ و $\overrightarrow{M''M''''} = \overrightarrow{BC}$. بتطبيق شال: $\overrightarrow{MM''''} = \overrightarrow{MM''} + \overrightarrow{M''M''''} = \overrightarrow{AB} + \overrightarrow{BC} = \overrightarrow{AC}$. إذن تركيب انسحابَين متتاليَين يعطي انسحابًا شعاعه مجموع الشعاعَين الأصليَّين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('896f4d8e-0e34-5870-8775-7f52b4b92a18', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'A وB وC وD وE خمس نقاط. بسّط: $\overrightarrow{AC} - \overrightarrow{BC} + \overrightarrow{BD} - \overrightarrow{ED}$', '[{"id":"a","text":"$\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{CE}$"},{"id":"c","text":"$\\overrightarrow{AD}$"},{"id":"d","text":"$\\overrightarrow{AE}$"}]'::jsonb, 'd', 'نحوّل الطرح إلى جمع: $\overrightarrow{AC} - \overrightarrow{BC} = \overrightarrow{AC} + \overrightarrow{CB}$، وبشال ($\overrightarrow{AC} + \overrightarrow{CB} = \overrightarrow{AB}$). ثمّ $\overrightarrow{BD} - \overrightarrow{ED} = \overrightarrow{BD} + \overrightarrow{DE}$، وبشال $= \overrightarrow{BE}$. الناتج الكلّي: $\overrightarrow{AB} + \overrightarrow{BE} = \overrightarrow{AE}$ (شال مرّة أخرى). إذن النتيجة هي $\overrightarrow{AE}$.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('160fd90e-d7df-5bfc-94e0-7c35ae98bbb4', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'M نقطة. صورتها بالانسحاب ذي الشعاع $\overrightarrow{u}$ هي M''، ثمّ صورة M'' بالانسحاب ذي الشعاع $-\overrightarrow{u}$ هي M''''. ماذا يساوي $\overrightarrow{MM''''}$؟', '[{"id":"a","text":"$\\overrightarrow{0}$"},{"id":"b","text":"$2\\overrightarrow{u}$"},{"id":"c","text":"$\\overrightarrow{u}$"},{"id":"d","text":"$-\\overrightarrow{u}$"}]'::jsonb, 'a', 'من تعريف الانسحاب: $\overrightarrow{MM''} = \overrightarrow{u}$ و $\overrightarrow{M''M''''} = -\overrightarrow{u}$. بتطبيق شال: $\overrightarrow{MM''''} = \overrightarrow{MM''} + \overrightarrow{M''M''''} = \overrightarrow{u} + (-\overrightarrow{u}) = \overrightarrow{0}$. هذا يعني أنّ M'''' = M: تطبيق انسحاب ثمّ انسحابه المعاكس يعيد النقطة إلى مكانها. الانسحاب ذو الشعاع $-\overrightarrow{u}$ هو الانسحاب المعكوس للانسحاب ذي الشعاع $\overrightarrow{u}$.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('529b64f3-4a2a-5866-b77d-a883f9003aa4', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'ABCD متوازي أضلاع مركزه O، وI منتصف [AB]. ما هو $\overrightarrow{OA} + \overrightarrow{OB}$؟', '[{"id":"a","text":"$\\overrightarrow{OC}$"},{"id":"b","text":"$2\\overrightarrow{OI}$"},{"id":"c","text":"$\\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{AB}$"}]'::jsonb, 'b', 'I منتصف [AB]، فبالخاصيّة العامّة للمنتصف: لأيّ نقطة O، $\overrightarrow{OA} + \overrightarrow{OB} = 2\overrightarrow{OI}$. التحقّق: $\overrightarrow{OA} + \overrightarrow{OB} = \overrightarrow{OI} + \overrightarrow{IA} + \overrightarrow{OI} + \overrightarrow{IB} = 2\overrightarrow{OI} + (\overrightarrow{IA} + \overrightarrow{IB})$، ولأنّ I منتصف [AB] فـ$\overrightarrow{IA} + \overrightarrow{IB} = \overrightarrow{0}$، إذن الناتج $= 2\overrightarrow{OI}$. (الخيار c خطأ لأنّ O مركز القطريَّين وليس قطعة [AB].)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6c6381e-0ba0-5e85-b3b5-1cc4ea5d7faa', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'ABDE متوازي أضلاع، وC منتصف [AE]. احسب: $\overrightarrow{CA} + \overrightarrow{CB} + \overrightarrow{CD} + \overrightarrow{CE}$', '[{"id":"a","text":"$2\\overrightarrow{AB}$"},{"id":"b","text":"$\\overrightarrow{0}$"},{"id":"c","text":"$2\\overrightarrow{AE}$"},{"id":"d","text":"$\\overrightarrow{BD}$"}]'::jsonb, 'a', 'لأنّ C منتصف [AE]: $\overrightarrow{CA} + \overrightarrow{CE} = \overrightarrow{0}$ (خاصيّة المنتصف). الآن نحسب $\overrightarrow{CB} + \overrightarrow{CD}$: بشال $\overrightarrow{CB} = \overrightarrow{CA} + \overrightarrow{AB}$ و $\overrightarrow{CD} = \overrightarrow{CE} + \overrightarrow{ED}$. لأنّ ABDE متوازي أضلاع فـ$\overrightarrow{ED} = \overrightarrow{AB}$، إذن $\overrightarrow{CD} = \overrightarrow{CE} + \overrightarrow{AB}$. المجموع: $\overrightarrow{CB} + \overrightarrow{CD} = (\overrightarrow{CA} + \overrightarrow{AB}) + (\overrightarrow{CE} + \overrightarrow{AB}) = (\overrightarrow{CA} + \overrightarrow{CE}) + 2\overrightarrow{AB} = \overrightarrow{0} + 2\overrightarrow{AB} = 2\overrightarrow{AB}$. الناتج الكلّي: $\overrightarrow{0} + 2\overrightarrow{AB} = 2\overrightarrow{AB}$.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

