INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b458517-ac01-509a-8c23-f0dda8c64a2f', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'ABCD متوازي أضلاع. أيّ مساواة صحيحة دائمًا؟', '[{"id":"a","text":"$\\overrightarrow{AB} = \\overrightarrow{DC}$"},{"id":"b","text":"$\\overrightarrow{AB} = \\overrightarrow{CD}$"},{"id":"c","text":"$\\overrightarrow{AB} = \\overrightarrow{BC}$"},{"id":"d","text":"$\\overrightarrow{AC} = \\overrightarrow{BD}$"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD يكون الضلعان [AB] و[DC] متوازيَين ومتساويَين وبالاتّجاه نفسه، إذن $\overrightarrow{AB} = \overrightarrow{DC}$. أمّا $\overrightarrow{CD}$ فهو الشعاع المعاكس.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc6fd815-3864-588a-afcc-0bcbfccd1ce3', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'في الانسحاب الذي شعاعه $\overrightarrow{u}$، صورة النقطة A هي A''. ما العلاقة بين النقاط؟', '[{"id":"a","text":"$\\overrightarrow{AA''} = \\overrightarrow{u}$"},{"id":"b","text":"$\\overrightarrow{A''A} = \\overrightarrow{u}$"},{"id":"c","text":"$\\overrightarrow{AA''} = \\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{AA''} = 2\\overrightarrow{u}$"}]'::jsonb, 'a', 'تعريف الانسحاب ذي الشعاع $\overrightarrow{u}$: كلّ نقطة M وصورتها M'' تحقّقان $\overrightarrow{MM''} = \overrightarrow{u}$. إذن للنقطة A: $\overrightarrow{AA''} = \overrightarrow{u}$.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21ca47be-6794-51f0-8fea-5408c9214d64', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'I منتصف القطعة [AB]. أيّ مساواة صحيحة؟', '[{"id":"a","text":"$\\overrightarrow{IA} + \\overrightarrow{IB} = \\overrightarrow{0}$"},{"id":"b","text":"$\\overrightarrow{IA} = \\overrightarrow{IB}$"},{"id":"c","text":"$\\overrightarrow{AI} = \\overrightarrow{BI}$"},{"id":"d","text":"$\\overrightarrow{IA} + \\overrightarrow{IB} = \\overrightarrow{AB}$"}]'::jsonb, 'a', 'بما أنّ I منتصف [AB] فإنّ $\overrightarrow{IA}$ و$\overrightarrow{IB}$ متساويان في الطول ومتعاكسان في الاتّجاه، أي $\overrightarrow{IB} = -\overrightarrow{IA}$، ومجموعهما $\overrightarrow{0}$.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2aa4dc51-0b7d-53b4-bdb6-2cf08ff2336b', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط: $\overrightarrow{AB} - \overrightarrow{CB}$', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$\\overrightarrow{CA}$"},{"id":"c","text":"$\\overrightarrow{AB} + \\overrightarrow{BC}$ يساوي $\\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{BA}$"}]'::jsonb, 'a', 'نحوّل الطرح إلى جمع بالشعاع المعاكس: $\overrightarrow{AB} - \overrightarrow{CB} = \overrightarrow{AB} + \overrightarrow{BC}$ (لأنّ $-\overrightarrow{CB} = \overrightarrow{BC}$). بشال: $= \overrightarrow{AC}$.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

