  ('8a45a71b-b2f9-5c7c-ad4d-674eab139c61', '67e1970d-7e67-5193-acd3-1729b90b0cb2', 'math', 'تمرين: الإحداثيّات والمسافات في المعلّم', 2, 65, 13, 'practice', 'admin', 1)
