  ('244944cd-952e-56c0-91ae-7dde1326a5d6', '67e1970d-7e67-5193-acd3-1729b90b0cb2', 'math', '⚔️ زعيم الفصل: المعلّم في المستوي — المعركة الكبرى', 3, 120, 30, 'boss', 'admin', 2)
