INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48cb8baf-edce-5753-8d55-cbb25021aa96', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(−2 ; 1) وB(4 ; 5). نقطة C(1 ; 3). هل C هي منتصف [AB]؟', '[{"id":"a","text":"لا، لأنّ المنتصف هو (1 ; 2)"},{"id":"b","text":"نعم، لأنّ $\\frac{-2+4}{2}=1$ و $\\frac{1+5}{2}=3$"},{"id":"c","text":"لا، لأنّ المنتصف هو (2 ; 3)"},{"id":"d","text":"لا، لأنّ المنتصف هو (1 ; 4)"}]'::jsonb, 'b', 'نحسب المنتصف: $\left(\frac{-2+4}{2} ; \frac{1+5}{2}\right) = \left(\frac{2}{2} ; \frac{6}{2}\right) = (1 ; 3)$. وبما أنّ C(1 ; 3) فإنّ C هي منتصف [AB].', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('76e96ca3-6af2-53b7-a308-fac16e21ce20', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(0 ; 3) وB(4 ; 0). ما المسافة AB؟', '[{"id":"a","text":"7"},{"id":"b","text":"√7"},{"id":"c","text":"√5"},{"id":"d","text":"5"}]'::jsonb, 'd', '$AB = \sqrt{(4-0)^2+(0-3)^2} = \sqrt{16+9} = \sqrt{25} = 5$.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a0d2297-0ecc-5787-ac5a-94aa07e50e80', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'ABCD متوازي أضلاع بـ A(1 ; 2) وB(5 ; 2) وC(6 ; 5). ما إحداثيّات D؟', '[{"id":"a","text":"D(3 ; 5)"},{"id":"b","text":"D(2 ; 5)"},{"id":"c","text":"D(7 ; 5)"},{"id":"d","text":"D(0 ; 5)"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: $\overrightarrow{AB} = \overrightarrow{DC}$. $\overrightarrow{AB} = (4;0)$. $\overrightarrow{DC} = (4;0)$ أي $C - D = (4;0)$ فـD = C − (4;0) = (6−4 ; 5−0) = (2 ; 5). التحقّق: $\overrightarrow{AD}=(1;3)$ و $\overrightarrow{BC}=(1;3)$ متساويان ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7359118-a246-5e74-affa-d0f61216527d', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(2 ; −1) وB(6 ; −1) وC(6 ; 4). هل المثلّث ABC قائم الزاوية؟ وأين القائمة؟', '[{"id":"a","text":"نعم، القائمة في A لأنّ $AB^2 + AC^2 = BC^2$"},{"id":"b","text":"لا، ليس قائمًا"},{"id":"c","text":"نعم، القائمة في B لأنّ $AB^2 + BC^2 = AC^2$"},{"id":"d","text":"نعم، القائمة في C لأنّ $AC^2 + BC^2 = AB^2$"}]'::jsonb, 'c', '$AB = \sqrt{(6-2)^2+0^2} = 4$، $BC = \sqrt{0^2+(4+1)^2} = 5$، $AC = \sqrt{(6-2)^2+(4+1)^2} = \sqrt{16+25} = \sqrt{41}$. نتحقّق: $AB^2 + BC^2 = 16+25 = 41 = AC^2$ ✓. إذن القائمة في B.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
