INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('921d1b5c-4236-5b2b-b91b-0d8f42878f2f', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(1 ; 2) وB(5 ; 8). ما إحداثيّات منتصف القطعة [AB]؟', '[{"id":"a","text":"(3 ; 5)"},{"id":"b","text":"(4 ; 6)"},{"id":"c","text":"(6 ; 10)"},{"id":"d","text":"(2 ; 3)"}]'::jsonb, 'a', 'المنتصف $I = \left(\frac{1+5}{2} ; \frac{2+8}{2}\right) = \left(\frac{6}{2} ; \frac{10}{2}\right) = (3 ; 5)$.', 1)
