INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7480e0a4-f226-58b8-b9d5-759d07fafb6c', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(1 ; 1) وB(4 ; 5). ما المسافة AB؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"√7"},{"id":"d","text":"√41"}]'::jsonb, 'a', '$AB = \sqrt{(4-1)^2 + (5-1)^2} = \sqrt{3^2 + 4^2} = \sqrt{9 + 16} = \sqrt{25} = 5$.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54e80fdb-1f52-55db-b4f4-77bf29f98fb4', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(−1 ; 2) وB(3 ; 2). ما إحداثيّات الشعاع $\overrightarrow{AB}$؟', '[{"id":"a","text":"(4 ; 0)"},{"id":"b","text":"(2 ; 4)"},{"id":"c","text":"(−4 ; 0)"},{"id":"d","text":"(2 ; 0)"}]'::jsonb, 'a', '$\overrightarrow{AB} = (x_B - x_A ; y_B - y_A) = (3 - (-1) ; 2 - 2) = (4 ; 0)$.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2eeb1f26-7df6-5d41-a80e-ed3e39328bd1', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'ABCD متوازي أضلاع بـ A(0 ; 0) وB(4 ; 1) وD(1 ; 3). ما إحداثيّات C؟', '[{"id":"a","text":"C(5 ; 4)"},{"id":"b","text":"C(3 ; 2)"},{"id":"c","text":"C(5 ; 1)"},{"id":"d","text":"C(4 ; 4)"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD: $\overrightarrow{AB} = \overrightarrow{DC}$. $\overrightarrow{AB} = (4 ; 1)$، إذن $C = D + (4 ; 1) = (1+4 ; 3+1) = (5 ; 4)$. التحقّق: $\overrightarrow{AD} = (1;3)$ و$\overrightarrow{BC} = (1;3)$ ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5474864-0c4c-5a96-a6ce-e7028ab46829', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(2 ; 1) وB(6 ; 1) وC(2 ; 4). هل المثلّث ABC قائم الزاوية؟ وأين القائمة؟', '[{"id":"a","text":"نعم، القائمة في A"},{"id":"b","text":"نعم، القائمة في B"},{"id":"c","text":"نعم، القائمة في C"},{"id":"d","text":"لا، ليس قائمًا"}]'::jsonb, 'a', '$AB = \sqrt{(6-2)^2+0^2} = 4$، $AC = \sqrt{0^2+(4-1)^2} = 3$، $BC = \sqrt{(2-6)^2+(4-1)^2} = \sqrt{16+9} = 5$. نتحقّق: $AB^2 + AC^2 = 16+9 = 25 = BC^2$ ✓. إذن القائمة في A.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89fd3865-98f6-5a03-9663-21869c46aa69', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(−2 ; 0) وB(2 ; 3). ما إحداثيّات النقطة C بحيث $\overrightarrow{AC} = 3\overrightarrow{AB}$؟', '[{"id":"a","text":"C(10 ; 9)"},{"id":"b","text":"C(6 ; 9)"},{"id":"c","text":"C(12 ; 9)"},{"id":"d","text":"C(4 ; 9)"}]'::jsonb, 'a', '$\overrightarrow{AB} = (2-(-2) ; 3-0) = (4 ; 3)$. إذن $3\overrightarrow{AB} = (12 ; 9)$. $C = A + (12 ; 9) = (-2+12 ; 0+9) = (10 ; 9)$.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

