INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d3df261-f148-5b0b-84a6-74ef0aa0e9c4', '00789172-89dd-5cc2-8af9-730645c3c113', 'كرة نصف قطرها 3 cm وأسطوانة نصف قطرها 3 cm وارتفاعها 4 cm. أيّهما حجمه أكبر؟', '[{"id":"a","text":"الكرة أكبر"},{"id":"b","text":"الأسطوانة أكبر"},{"id":"c","text":"حجماهما متساويان"},{"id":"d","text":"لا يمكن المقارنة"}]'::jsonb, 'c', 'حجم الكرة: $V_K = \frac{4}{3}\pi \times 3^3 = \frac{4}{3} \times 27\pi = 36\pi \text{ cm}^3$. حجم الأسطوانة: $V_A = \pi \times 3^2 \times 4 = 36\pi \text{ cm}^3$. الحجمان متساويان! هذه نتيجة مدهشة تستحقّ الحفظ.', 4)
