INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03d725a0-aedc-5bd2-a40d-fa740eee3cba', '00789172-89dd-5cc2-8af9-730645c3c113', 'هرم قاعدته مربّع ضلعه 4 cm وارتفاعه 3 cm. إذا ضاعف الارتفاع فقط ليصبح 6 cm، فبكم يتضاعف الحجم؟', '[{"id":"a","text":"يتضاعف مرّتين (×2)"},{"id":"b","text":"يتضاعف ثلاث مرّات (×3)"},{"id":"c","text":"يتضاعف أربع مرّات (×4)"},{"id":"d","text":"يبقى كما هو"}]'::jsonb, 'a', '$V_1 = \frac{1}{3} \times 16 \times 3 = 16 \text{ cm}^3$. $V_2 = \frac{1}{3} \times 16 \times 6 = 32 \text{ cm}^3$. النسبة $V_2 / V_1 = 32/16 = 2$. الحجم يتضاعف مرّتين لأنّ صيغة الحجم خطّية في h.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
