INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db5b1cf9-ba85-585d-998f-e17a1ccbb96a', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 3 cm وارتفاعها 10 cm. ما حجمها؟ (π ≈ 3.14)', '[{"id":"a","text":"282.6 cm³"},{"id":"b","text":"94.2 cm³"},{"id":"c","text":"188.4 cm³"},{"id":"d","text":"565.2 cm³"}]'::jsonb, 'a', 'حجم الأسطوانة $V = \pi r^2 h$. نربّع نصف القطر: $r^2 = 3^2 = 9$. إذن $V = 3.14 \times 9 \times 10 = 3.14 \times 90 = 282.6 \text{ cm}^3$.', 1)
ON CONFLICT (id) DO UPDATE SET
