INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddbdd453-8143-53da-9bbe-497286ee59a3', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'مخروط نصف قطر قاعدته 3 cm وارتفاعه 4 cm. ما طوله المائل l؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"√7 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'a', 'الطول المائل $l = \sqrt{r^2 + h^2} = \sqrt{3^2 + 4^2} = \sqrt{9 + 16} = \sqrt{25} = 5 \text{ cm}$ (الثلاثية 3-4-5).', 2)
