  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('778771b1-984e-5b3f-b318-5f9ed781b359', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'هرم قاعدته مربّع ضلعه 6 cm وارتفاعه 10 cm. ما حجمه؟', '[{"id":"a","text":"120 cm³"},{"id":"b","text":"360 cm³"},{"id":"c","text":"60 cm³"},{"id":"d","text":"100 cm³"}]'::jsonb, 'a', 'مساحة القاعدة المربّعة $S = 6^2 = 36 \text{ cm}^2$. حجم الهرم $V = \frac{1}{3} \times S \times h = \frac{1}{3} \times 36 \times 10 = \frac{360}{3} = 120 \text{ cm}^3$.', 3)
