  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1410b5e-9143-5d13-91f1-297686628498', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'كرة نصف قطرها 6 cm. ما حجمها بدلالة π؟', '[{"id":"a","text":"288π cm³"},{"id":"b","text":"144π cm³"},{"id":"c","text":"72π cm³"},{"id":"d","text":"216π cm³"}]'::jsonb, 'a', 'حجم الكرة $V = \frac{4}{3}\pi r^3 = \frac{4}{3}\pi \times 6^3 = \frac{4}{3}\pi \times 216 = \frac{864}{3}\pi = 288\pi \text{ cm}^3$.', 4)
