INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba409a8e-709a-569b-8161-5bab65afffce', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 4 cm وارتفاعها 7 cm. ما مساحتها الجانبية؟ (π ≈ 3.14)', '[{"id":"a","text":"175.84 cm²"},{"id":"b","text":"87.92 cm²"},{"id":"c","text":"351.68 cm²"},{"id":"d","text":"100.48 cm²"}]'::jsonb, 'a', 'المساحة الجانبية للأسطوانة = محيط القاعدة × الارتفاع = $2\pi r h = 2 \times 3.14 \times 4 \times 7 = 6.28 \times 28 = 175.84 \text{ cm}^2$.', 5)
