INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af07c682-e2b7-5bf7-9de1-e4933dafb486', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'إذا ضاعفنا نصف قطر كرة (ليصبح 2r بدل r)، فبكم يتضاعف حجمها؟', '[{"id":"a","text":"8 مرّات (×8)"},{"id":"b","text":"مرّتين (×2)"},{"id":"c","text":"4 مرّات (×4)"},{"id":"d","text":"6 مرّات (×6)"}]'::jsonb, 'a', 'حجم الكرة $V = \frac{4}{3}\pi r^3$ متناسب مع مكعّب نصف القطر. عند مضاعفة r إلى 2r: $(2r)^3 = 8r^3$، إذن الحجم يتضاعف 8 مرّات.', 6)
