  ('377d74ea-0e11-5a70-9f62-2b390afb7c31', '0d636faa-337f-57db-a256-88d4ec85ca49', 'math', '👑 تحدّي النخبة: سبر شامل بمستوى الامتياز', 4, 300, 60, 'challenge', 'admin', 3)
